type ExpressionValidationIssue = {
  startOffset: number
  endOffset: number
  message: string
  severity: 'error' | 'warning'
}

function decodeJsonStringContent(raw: string): string {
  try {
    return JSON.parse(`"${raw}"`)
  } catch {
    return raw
  }
}

function tryExtractJsonParseErrorOffset(message: string): number | null {
  const text = String(message || '')
  const m = text.match(/position\s+(\d+)/i)
  if (!m) return null
  const value = Number(m[1])
  if (!Number.isFinite(value) || value < 0) return null
  return Math.floor(value)
}

function validateJsonTemplateSyntax(text: string): ExpressionValidationIssue[] {
  const source = String(text || '')
  const trimmed = source.trim()
  if (!trimmed) return []
  if (parseJsonTemplateLikeValue(source) !== null) return []
  try {
    JSON.parse(source)
    return []
  } catch (err: any) {
    const rawMessage = String(err?.message || 'Invalid JSON syntax')
    const pos = tryExtractJsonParseErrorOffset(rawMessage)
    const startOffset = Math.max(0, Math.min(source.length, pos ?? 0))
    const endOffset = Math.max(startOffset + 1, Math.min(source.length, startOffset + 1))
    return [
      {
        startOffset,
        endOffset,
        message: rawMessage,
        severity: 'error',
      },
    ]
  }
}

function extractExpressionStringRanges(text: string): Array<{ value: string; startOffset: number; endOffset: number }> {
  const out: Array<{ value: string; startOffset: number; endOffset: number }> = []
  let inString = false
  let quote: '"' | "'" | '`' | null = null
  let escaped = false
  let stringStart = -1
  let buffer = ''

  for (let i = 0; i < text.length; i += 1) {
    const ch = text[i]
    if (!inString) {
      if (ch === '"' || ch === "'" || ch === '`') {
        inString = true
        quote = ch
        escaped = false
        stringStart = i
        buffer = ''
      }
      continue
    }
    if (escaped) {
      buffer += ch
      escaped = false
      continue
    }
    if (ch === '\\') {
      buffer += ch
      escaped = true
      continue
    }
    if (ch === quote) {
      const decoded = quote === '"' ? decodeJsonStringContent(buffer) : buffer
      if (decoded.startsWith('=')) {
        out.push({
          value: decoded,
          startOffset: stringStart + 1,
          endOffset: i,
        })
      }
      inString = false
      quote = null
      escaped = false
      buffer = ''
      stringStart = -1
      continue
    }
    buffer += ch
  }

  return out
}

function collapseExpressionWhitespace(raw: string): string {
  const source = String(raw || '').trim()
  if (!source) return ''
  let out = ''
  let quote: '"' | "'" | null = null
  let escaped = false
  let pendingSpace = false

  const appendSpaceIfNeeded = (nextChar: string) => {
    if (!pendingSpace) return
    pendingSpace = false
    if (!out) return
    const last = out[out.length - 1]
    if (!last || /\s/.test(last)) return
    if (/[([{.]/.test(last)) return
    if (/[)\]},.:]/.test(nextChar)) return
    out += ' '
  }

  for (let i = 0; i < source.length; i += 1) {
    const ch = source[i]
    if (quote) {
      out += ch
      if (escaped) {
        escaped = false
        continue
      }
      if (ch === '\\') {
        escaped = true
        continue
      }
      if (ch === quote) quote = null
      continue
    }
    if (ch === '"' || ch === "'") {
      appendSpaceIfNeeded(ch)
      quote = ch
      out += ch
      continue
    }
    if (/\s/.test(ch)) {
      pendingSpace = true
      continue
    }
    appendSpaceIfNeeded(ch)
    out += ch
  }
  return out.trim()
}

function findNextNonWhitespaceChar(source: string, start: number): string {
  for (let i = Math.max(0, start); i < source.length; i += 1) {
    const ch = source[i]
    if (!/\s/.test(ch)) return ch
  }
  return ''
}

function getLastNonWhitespaceChar(source: string): string {
  for (let i = source.length - 1; i >= 0; i -= 1) {
    const ch = source[i]
    if (!/\s/.test(ch)) return ch
  }
  return ''
}

function formatStructuredLiteral(source: string): string {
  const text = collapseExpressionWhitespace(source)
  if (!text) return ''

  let out = ''
  let quote: '"' | "'" | null = null
  let escaped = false
  let depthCurly = 0
  let depthSquare = 0
  let depthRound = 0
  const indentUnit = '  '

  const blockDepth = () => Math.max(0, depthCurly + depthSquare)
  const appendIndent = () => {
    out += indentUnit.repeat(blockDepth())
  }
  const appendNewline = () => {
    out = out.replace(/[ \t]+$/g, '')
    if (!out.endsWith('\n')) out += '\n'
    appendIndent()
  }
  const appendTokenSpaceIfNeeded = () => {
    if (!out) return
    const last = out[out.length - 1]
    if (last === ' ' || last === '\n') return
    out += ' '
  }

  for (let i = 0; i < text.length; i += 1) {
    const ch = text[i]
    if (quote) {
      out += ch
      if (escaped) {
        escaped = false
        continue
      }
      if (ch === '\\') {
        escaped = true
        continue
      }
      if (ch === quote) quote = null
      continue
    }

    if (ch === '"' || ch === "'") {
      quote = ch
      out += ch
      continue
    }

    if (/\s/.test(ch)) {
      appendTokenSpaceIfNeeded()
      continue
    }

    if (ch === '{' || ch === '[') {
      out += ch
      if (ch === '{') depthCurly += 1
      else depthSquare += 1
      const next = findNextNonWhitespaceChar(text, i + 1)
      const isEmptyBlock = (ch === '{' && next === '}') || (ch === '[' && next === ']')
      if (!isEmptyBlock && next) appendNewline()
      continue
    }

    if (ch === '}') {
      depthCurly = Math.max(0, depthCurly - 1)
      if (getLastNonWhitespaceChar(out) !== '{') appendNewline()
      out += ch
      continue
    }

    if (ch === ']') {
      depthSquare = Math.max(0, depthSquare - 1)
      if (getLastNonWhitespaceChar(out) !== '[') appendNewline()
      out += ch
      continue
    }

    if (ch === '(') {
      depthRound += 1
      out += ch
      continue
    }

    if (ch === ')') {
      depthRound = Math.max(0, depthRound - 1)
      out += ch
      continue
    }

    if (ch === ',') {
      out += ','
      if (depthRound === 0) appendNewline()
      else out += ' '
      continue
    }

    if (ch === ':') {
      out = out.replace(/[ \t]+$/g, '')
      out += ': '
      continue
    }

    out += ch
  }

  return String(out || '')
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim()
}

function indentMultilineExpression(text: string, depth: number, indentUnit = '  '): string {
  const prefix = indentUnit.repeat(Math.max(0, depth))
  return String(text || '')
    .split('\n')
    .map((line) => `${prefix}${line}`)
    .join('\n')
}

function shouldMultilineFunctionCall(name: string, args: string[], inlineCandidate: string): boolean {
  const fn = String(name || '').trim().toLowerCase()
  const forceMultiline = new Set([
    'if_',
    'group_aggregate',
    'rolling_update',
    'agg_if',
    'count_if',
    'sum_if',
    'mean_if',
    'min_if',
    'max_if',
    'distinct_if',
    'distinct_count_if',
    'count_non_null_if',
  ])
  if (forceMultiline.has(fn)) return true
  if (args.length >= 4) return true
  if (inlineCandidate.length > 96) return true
  return args.some((arg) => {
    const text = String(arg || '')
    if (text.includes('\n')) return true
    if (text.length > 44) return true
    return false
  })
}

function formatExpressionBody(source: string): string {
  const text = collapseExpressionWhitespace(source)
  if (!text) return ''
  const call = parseTopLevelFunctionCallSource(text)
  if (!call) return text

  const formattedArgs = call.args.map((arg) => formatExpressionBody(String(arg || '')))
  const inline = `${call.name}(${formattedArgs.join(', ')})`
  if (!formattedArgs.length || !shouldMultilineFunctionCall(call.name, formattedArgs, inline)) {
    return inline
  }

  const argsBlock = formattedArgs
    .map((arg) => indentMultilineExpression(arg, 1))
    .join(',\n')
  return `${call.name}(\n${argsBlock}\n)`
}

function beautifyExpressionText(rawExpression: string): string {
  const source = String(rawExpression || '').trim()
  if (!source) return ''
  const hasEqualsPrefix = source.startsWith('=')
  const body = hasEqualsPrefix ? source.slice(1).trim() : source
  if (!body) return hasEqualsPrefix ? '=' : ''

  // Support users who paste JSON object templates into Expression mode.
  // If it is valid JSON and not a normal "=expr", apply JSON+expression beautify.
  if (!hasEqualsPrefix && /^[\[{]/.test(body)) {
    const parsed = parseJsonTemplateLikeValue(body)
    if (parsed !== null) {
      const beautified = beautifyJsonTemplateNode(parsed)
      return JSON.stringify(beautified, null, 2)
    }
    // Not valid JSON/JS-like template; continue with regular expression formatting.
  }

  const parsedTopLevelCall = parseTopLevelFunctionCallSource(body)
  const formattedBody = (
    parsedTopLevelCall
      ? formatExpressionBody(body)
      : /^[\[{]/.test(body)
        ? formatStructuredLiteral(body)
        : collapseExpressionWhitespace(body)
  )
  const normalized = String(formattedBody || body)
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim()
  return hasEqualsPrefix ? `=${normalized}` : normalized
}

function beautifyExpressionForJsonString(rawExpression: string): string {
  const formatted = beautifyExpressionText(rawExpression)
  const hasEqualsPrefix = formatted.startsWith('=')
  const body = hasEqualsPrefix ? formatted.slice(1) : formatted
  const compact = collapseExpressionWhitespace(body)
  return hasEqualsPrefix ? `=${compact}` : compact
}

function toJsPropertyKey(key: string): string {
  const normalized = String(key || '')
  return JSON.stringify(normalized)
}

function toJsViewTemplateText(
  value: unknown,
  depth = 0,
  options?: {
    beautifyExpressions?: boolean
  }
): string {
  const indentUnit = '  '
  const indent = indentUnit.repeat(Math.max(0, depth))
  const nextIndent = indentUnit.repeat(Math.max(0, depth + 1))
  const beautifyExpressions = options?.beautifyExpressions !== false

  if (typeof value === 'string') {
    const text = String(value || '')
    if (text.trim().startsWith('=')) {
      const expressionText = beautifyExpressions ? beautifyExpressionText(text) : text
      const escaped = expressionText
        .replace(/\\/g, '\\\\')
        .replace(/"/g, '\\"')
      return `"${escaped}"`
    }
    return JSON.stringify(text)
  }
  if (typeof value === 'number' || typeof value === 'boolean' || value === null) {
    return JSON.stringify(value)
  }
  if (Array.isArray(value)) {
    if (value.length === 0) return '[]'
    const rows = value.map((item) => `${nextIndent}${toJsViewTemplateText(item, depth + 1, options)}`)
    return `[\n${rows.join(',\n')}\n${indent}]`
  }
  if (value && typeof value === 'object') {
    const entries = Object.entries(value as Record<string, unknown>)
    if (entries.length === 0) return '{}'
    const rows = entries.map(([key, child]) =>
      `${nextIndent}${toJsPropertyKey(key)}: ${toJsViewTemplateText(child, depth + 1, options)}`
    )
    return `{\n${rows.join(',\n')}\n${indent}}`
  }
  return JSON.stringify(value)
}

function beautifyJsonTemplateNode(value: unknown): unknown {
  if (typeof value === 'string') {
    const text = String(value || '').trim()
    if (!text.startsWith('=')) return value
    return beautifyExpressionForJsonString(text)
  }
  if (Array.isArray(value)) {
    return value.map((item) => beautifyJsonTemplateNode(item))
  }
  if (value && typeof value === 'object') {
    const obj = value as Record<string, unknown>
    const next: Record<string, unknown> = {}
    Object.entries(obj).forEach(([key, child]) => {
      next[key] = beautifyJsonTemplateNode(child)
    })
    return next
  }
  return value
}

function beautifyJsonTemplateText(raw: string, style: CustomBeautifyStyle = 'json'): string {
  const source = String(raw || '').trim()
  if (!source) return style === 'js_view' ? '{\n}' : '{\n}'
  const parsed = parseJsonTemplateLikeValue(source)
  if (parsed === null) throw new Error('Invalid JSON/JS template syntax')
  const beautified = beautifyJsonTemplateNode(parsed)
  if (style === 'js_view') {
    return toJsViewTemplateText(beautified, 0)
  }
  return JSON.stringify(beautified, null, 2)
}

type ExpressionFunctionCallRef = {
  name: string
  nameStart: number
  openParenOffset: number
  closeParenOffset: number
  argsSource: string
}

type ParsedArgSegment = {
  text: string
  startOffset: number
  endOffset: number
}

function decodeSingleQuotedLiteral(raw: string): string {
  return String(raw || '')
    .replace(/\\\\/g, '\\')
    .replace(/\\'/g, "'")
}

function buildQuoteMask(source: string): boolean[] {
  const mask = Array(source.length).fill(false)
  let quote: '"' | "'" | null = null
  let escaped = false
  for (let i = 0; i < source.length; i += 1) {
    const ch = source[i]
    if (quote) {
      mask[i] = true
      if (escaped) {
        escaped = false
        continue
      }
      if (ch === '\\') {
        escaped = true
        continue
      }
      if (ch === quote) {
        quote = null
      }
      continue
    }
    if (ch === '"' || ch === "'") {
      quote = ch
      mask[i] = true
    }
  }
  return mask
}

function findMatchingParenOffset(source: string, openOffset: number): number {
  let depth = 0
  let quote: '"' | "'" | null = null
  let escaped = false
  for (let i = openOffset; i < source.length; i += 1) {
    const ch = source[i]
    if (quote) {
      if (escaped) {
        escaped = false
        continue
      }
      if (ch === '\\') {
        escaped = true
        continue
      }
      if (ch === quote) {
        quote = null
      }
      continue
    }
    if (ch === '"' || ch === "'") {
      quote = ch
      continue
    }
    if (ch === '(') {
      depth += 1
      continue
    }
    if (ch === ')') {
      depth -= 1
      if (depth === 0) return i
    }
  }
  return -1
}

function collectExpressionFunctionCalls(source: string): ExpressionFunctionCallRef[] {
  const refs: ExpressionFunctionCallRef[] = []
  if (!source) return refs
  const quoteMask = buildQuoteMask(source)
  const matcher = /\b([A-Za-z_]\w*)\s*\(/g
  let match = matcher.exec(source)
  while (match) {
    const name = String(match[1] || '')
    const nameStart = Number(match.index || 0)
    if (!quoteMask[nameStart]) {
      const openParenOffset = source.indexOf('(', nameStart + name.length)
      if (openParenOffset >= 0 && !quoteMask[openParenOffset]) {
        const closeParenOffset = findMatchingParenOffset(source, openParenOffset)
        if (closeParenOffset > openParenOffset) {
          refs.push({
            name,
            nameStart,
            openParenOffset,
            closeParenOffset,
            argsSource: source.slice(openParenOffset + 1, closeParenOffset),
          })
        }
      }
    }
    match = matcher.exec(source)
  }
  return refs
}

function splitTopLevelArgsWithOffsets(argsSource: string): ParsedArgSegment[] {
  const segments: ParsedArgSegment[] = []
  let start = 0
  let depthRound = 0
  let depthSquare = 0
  let depthCurly = 0
  let quote: '"' | "'" | null = null
  let escaped = false

  for (let i = 0; i < argsSource.length; i += 1) {
    const ch = argsSource[i]
    if (quote) {
      if (escaped) {
        escaped = false
        continue
      }
      if (ch === '\\') {
        escaped = true
        continue
      }
      if (ch === quote) {
        quote = null
      }
      continue
    }

    if (ch === '"' || ch === "'") {
      quote = ch
      continue
    }
    if (ch === '(') depthRound += 1
    else if (ch === ')') depthRound = Math.max(0, depthRound - 1)
    else if (ch === '[') depthSquare += 1
    else if (ch === ']') depthSquare = Math.max(0, depthSquare - 1)
    else if (ch === '{') depthCurly += 1
    else if (ch === '}') depthCurly = Math.max(0, depthCurly - 1)
    else if (ch === ',' && depthRound === 0 && depthSquare === 0 && depthCurly === 0) {
      segments.push({
        text: argsSource.slice(start, i),
        startOffset: start,
        endOffset: i,
      })
      start = i + 1
    }
  }

  segments.push({
    text: argsSource.slice(start),
    startOffset: start,
    endOffset: argsSource.length,
  })
  return segments
}

function extractQuotedLiteralFromSegment(segment: ParsedArgSegment): { value: string; startOffset: number; endOffset: number } | null {
  const text = segment.text
  if (!text) return null
  const singleQuoteOffset = text.indexOf("'")
  const doubleQuoteOffset = text.indexOf('"')
  const firstQuote = (
    singleQuoteOffset >= 0 && doubleQuoteOffset >= 0
      ? Math.min(singleQuoteOffset, doubleQuoteOffset)
      : singleQuoteOffset >= 0
        ? singleQuoteOffset
        : doubleQuoteOffset
  )
  if (firstQuote < 0 || text.slice(0, firstQuote).trim()) return null
  const quoteChar = text[firstQuote]
  let escaped = false
  for (let i = firstQuote + 1; i < text.length; i += 1) {
    const ch = text[i]
    if (escaped) {
      escaped = false
      continue
    }
    if (ch === '\\') {
      escaped = true
      continue
    }
    if (ch === quoteChar) {
      if (text.slice(i + 1).trim()) return null
      const raw = text.slice(firstQuote + 1, i)
      return {
        value: String(raw || '')
          .replace(/\\\\/g, '\\')
          .replace(/\\'/g, "'")
          .replace(/\\"/g, '"'),
        startOffset: segment.startOffset + firstQuote + 1,
        endOffset: segment.startOffset + i,
      }
    }
  }
  return null
}

function isAllowedFieldName(fieldName: string, validationContext: ExpressionValidationContext): boolean {
  const normalized = String(fieldName || '').trim()
  if (!normalized) return true
  if (!validationContext.allowedFieldNames.size && !validationContext.allowedFieldNamesLower.size) return true
  if (validationContext.allowedFieldNames.has(normalized)) return true
  return validationContext.allowedFieldNamesLower.has(normalized.toLowerCase())
}

function levenshteinDistance(a: string, b: string): number {
  const x = String(a || '')
  const y = String(b || '')
  const n = x.length
  const m = y.length
  if (n === 0) return m
  if (m === 0) return n
  const dp: number[][] = Array.from({ length: n + 1 }, () => Array(m + 1).fill(0))
  for (let i = 0; i <= n; i += 1) dp[i][0] = i
  for (let j = 0; j <= m; j += 1) dp[0][j] = j
  for (let i = 1; i <= n; i += 1) {
    for (let j = 1; j <= m; j += 1) {
      const cost = x[i - 1] === y[j - 1] ? 0 : 1
      dp[i][j] = Math.min(
        dp[i - 1][j] + 1,
        dp[i][j - 1] + 1,
        dp[i - 1][j - 1] + cost,
      )
    }
  }
  return dp[n][m]
}

function findClosestSuggestion(value: string, candidates: string[]): string | null {
  const source = String(value || '').trim().toLowerCase()
  if (!source) return null
  const normalizedCandidates = uniqueFieldNames(candidates || []).filter(Boolean)
  if (!normalizedCandidates.length) return null

  const exact = normalizedCandidates.find((candidate) => candidate.toLowerCase() === source)
  if (exact) return exact

  const startsWithMatch = normalizedCandidates
    .filter((candidate) => candidate.toLowerCase().startsWith(source))
    .sort((a, b) => a.length - b.length)[0]
  if (startsWithMatch) return startsWithMatch

  let bestCandidate: string | null = null
  let bestScore = Number.POSITIVE_INFINITY
  normalizedCandidates.forEach((candidate) => {
    const score = levenshteinDistance(source, candidate.toLowerCase())
    if (score < bestScore) {
      bestScore = score
      bestCandidate = candidate
    }
  })

  if (!bestCandidate) return null
  const threshold = Math.max(2, Math.floor(source.length * 0.4))
  return bestScore <= threshold ? bestCandidate : null
}

function isAllowedPathName(pathName: string, validationContext: ExpressionValidationContext): boolean {
  const normalized = String(pathName || '').trim()
  if (!normalized) return true
  if (!validationContext.allowedPathNames.size && !validationContext.allowedPathNamesLower.size) return true
  if (validationContext.allowedPathNames.has(normalized)) return true
  return validationContext.allowedPathNamesLower.has(normalized.toLowerCase())
}

function extractPathRoot(pathName: string): string {
  const normalized = String(pathName || '').trim()
  if (!normalized) return ''
  const rootMatch = normalized.match(/^[^.[\]]+/)
  return String(rootMatch?.[0] || '').trim()
}

function withSuggestion(message: string, suggestion: string | null): string {
  const base = String(message || '')
  const hint = String(suggestion || '').trim()
  if (!hint) return base
  return `${base}. Did you mean "${hint}"?`
}

function validateExpressionSemantics(
  source: string,
  baseOffset: number,
  validationContext: ExpressionValidationContext
): ExpressionValidationIssue[] {
  const issues: ExpressionValidationIssue[] = []
  const seen = new Set<string>()
  const quoteMask = buildQuoteMask(source)
  const functionRefs = collectExpressionFunctionCalls(source)
  const conditionFunctions = new Set([
    'count_if',
    'sum_if',
    'mean_if',
    'min_if',
    'max_if',
    'distinct_if',
    'distinct_count_if',
    'count_non_null_if',
  ])
  const profilePathFirstArgFunctions = new Set([
    'inc',
    'map_inc',
    'append_unique',
    'rolling_update',
    'unique_metrics',
    'unique_group_aggregate',
    'unique_signal',
    'unique_count',
    'unique_sum',
    'unique_avg',
    'unique_min',
    'unique_max',
    'unique_stats',
    'unique_metric',
    'unique_ratio',
    'unique_rate',
    'unique_flag',
    'unique_map',
    'top_key',
    'unique_interval',
    'unique_velocity',
    'burst_flag',
    'metric_get',
    'entropy_update',
    'min_update',
    'max_update',
    'repetition_rate',
    'change_rate',
    'geo_variance',
    'geo_conflict_flag',
    'unique_rolling',
    'unique_window',
    'window_sum',
    'window_avg',
    'trend_flag',
    'anomaly_detection',
    'anamoly_detection',
    'anomaly_group_aggregate',
    'anamoly_group_aggregate',
    'sequence_update',
    'loop_flag',
    'repeated_sequence',
    'unique_sequence',
    'unique_geo',
    'partition_count',
    'partition_avg',
    'partition_stddev',
    'partition_percentile',
    'partition_zscore',
    'sigma_threshold',
    'threshold_reason',
    'zscore_threshold_flag',
  ])

  const addIssue = (issue: ExpressionValidationIssue) => {
    const key = `${issue.startOffset}:${issue.endOffset}:${issue.message}`
    if (seen.has(key)) return
    seen.add(key)
    issues.push(issue)
  }

  // Validate callable names even if the expression is partially malformed.
  // This catches typos like feild(), innc(), group_aggrigate() early.
  const callMatcher = /\b([A-Za-z_]\w*)\s*\(/g
  let callMatch = callMatcher.exec(source)
  while (callMatch) {
    const fnName = String(callMatch[1] || '')
    const fnStart = Number(callMatch.index || 0)
    if (fnName && !quoteMask[fnStart]) {
      const fnLower = fnName.toLowerCase()
      if (!validationContext.allowedFunctionNames.has(fnLower)) {
        const fnSuggestion = findClosestSuggestion(fnName, Array.from(validationContext.allowedFunctionNames))
        addIssue({
          startOffset: baseOffset + fnStart,
          endOffset: baseOffset + fnStart + fnName.length,
          message: withSuggestion(`Function "${fnName}" is not available`, fnSuggestion),
          severity: 'error',
        })
      }
    }
    callMatch = callMatcher.exec(source)
  }

  const markUnknownField = (fieldName: string, startOffset: number, endOffset: number, contextLabel: string) => {
    if (isAllowedFieldName(fieldName, validationContext)) return
    const fieldSuggestion = findClosestSuggestion(fieldName, Array.from(validationContext.allowedFieldNames))
    addIssue({
      startOffset: baseOffset + startOffset,
      endOffset: baseOffset + Math.max(startOffset + 1, endOffset),
      message: withSuggestion(`Field "${fieldName}" is not available (${contextLabel})`, fieldSuggestion),
      severity: 'error',
    })
  }

  const validatePathRootReference = (
    literalValue: string,
    literalStartOffset: number,
    contextLabel: string
  ) => {
    const pathText = String(literalValue || '').trim()
    if (!pathText) return
    const rootMatch = pathText.match(/^[^.[\]]+/)
    const root = String(rootMatch?.[0] || '').trim()
    if (!root) return
    const rootStart = literalStartOffset
    const rootEnd = literalStartOffset + root.length
    markUnknownField(root, rootStart, rootEnd, `${contextLabel} path root`)
  }

  const validateFullPathReference = (
    literalValue: string,
    literalStartOffset: number,
    literalEndOffset: number,
    contextLabel: string
  ) => {
    const pathText = String(literalValue || '').trim()
    if (!pathText) return
    if (isAllowedPathName(pathText, validationContext)) return

    const root = extractPathRoot(pathText)
    if (!root) return

    if (!isAllowedFieldName(root, validationContext)) {
      const rootStart = literalStartOffset
      const rootEnd = literalStartOffset + root.length
      markUnknownField(root, rootStart, rootEnd, `${contextLabel} path root`)
      return
    }

    const sameRootCandidates = Array.from(validationContext.allowedPathNames).filter((candidate) => {
      const cRoot = extractPathRoot(candidate)
      return cRoot.toLowerCase() === root.toLowerCase()
    })

    if (sameRootCandidates.length === 0) return
    const suggestion = findClosestSuggestion(pathText, sameRootCandidates)
    addIssue({
      startOffset: baseOffset + literalStartOffset,
      endOffset: baseOffset + Math.max(literalStartOffset + 1, literalEndOffset),
      message: withSuggestion(`Path "${pathText}" is not available (${contextLabel})`, suggestion),
      severity: 'error',
    })
  }

  functionRefs.forEach((ref) => {
    const fnNameLower = ref.name.toLowerCase()
    if (!validationContext.allowedFunctionNames.has(fnNameLower)) {
      const fnSuggestion = findClosestSuggestion(ref.name, Array.from(validationContext.allowedFunctionNames))
      addIssue({
        startOffset: baseOffset + ref.nameStart,
        endOffset: baseOffset + ref.nameStart + ref.name.length,
        message: withSuggestion(`Function "${ref.name}" is not available`, fnSuggestion),
        severity: 'error',
      })
    }

    const args = splitTopLevelArgsWithOffsets(ref.argsSource)
    const fieldArgIndexes: number[] = []
    if (fnNameLower === 'field' || fnNameLower === 'values' || fnNameLower === 'prev') {
      fieldArgIndexes.push(0)
    } else if (fnNameLower === 'group_aggregate') {
      fieldArgIndexes.push(0)
    } else if (conditionFunctions.has(fnNameLower)) {
      fieldArgIndexes.push(0, 1)
    } else if (fnNameLower === 'agg_if') {
      fieldArgIndexes.push(0, 1)
    }

    fieldArgIndexes.forEach((argIdx) => {
      const segment = args[argIdx]
      if (!segment) return
      const literal = extractQuotedLiteralFromSegment(segment)
      if (!literal) return
      if (fnNameLower === 'prev' && /[.[\]]/.test(literal.value)) {
        validateFullPathReference(
          literal.value,
          ref.openParenOffset + 1 + literal.startOffset,
          ref.openParenOffset + 1 + literal.endOffset,
          `${ref.name}()`
        )
        validatePathRootReference(
          literal.value,
          ref.openParenOffset + 1 + literal.startOffset,
          `${ref.name}()`
        )
        return
      }
      markUnknownField(
        literal.value,
        ref.openParenOffset + 1 + literal.startOffset,
        ref.openParenOffset + 1 + literal.endOffset,
        `${ref.name}()`
      )
    })

    // Validate path-root for profile path helpers where first argument is a dotted path.
    if (profilePathFirstArgFunctions.has(fnNameLower)) {
      const firstArg = args[0]
      const firstLiteral = firstArg ? extractQuotedLiteralFromSegment(firstArg) : null
      if (firstLiteral && /[.[\]]/.test(firstLiteral.value)) {
        validateFullPathReference(
          firstLiteral.value,
          ref.openParenOffset + 1 + firstLiteral.startOffset,
          ref.openParenOffset + 1 + firstLiteral.endOffset,
          `${ref.name}()`
        )
        validatePathRootReference(
          firstLiteral.value,
          ref.openParenOffset + 1 + firstLiteral.startOffset,
          `${ref.name}()`
        )
      }
    }

    if (fnNameLower === 'loop_flag' || fnNameLower === 'burst_flag') {
      const secondArg = args[1]
      const secondLiteral = secondArg ? extractQuotedLiteralFromSegment(secondArg) : null
      if (secondLiteral && /[.[\]]/.test(secondLiteral.value)) {
        validateFullPathReference(
          secondLiteral.value,
          ref.openParenOffset + 1 + secondLiteral.startOffset,
          ref.openParenOffset + 1 + secondLiteral.endOffset,
          `${ref.name}()`
        )
        validatePathRootReference(
          secondLiteral.value,
          ref.openParenOffset + 1 + secondLiteral.startOffset,
          `${ref.name}()`
        )
      }
    }

    if (conditionFunctions.has(fnNameLower)) {
      const opArg = args[3]
      const opLiteral = opArg ? extractQuotedLiteralFromSegment(opArg) : null
      if (opLiteral) {
        const opLower = opLiteral.value.trim().toLowerCase()
        if (opLower && !EXPR_ALLOWED_CONDITION_OPERATORS.has(opLower)) {
          const opSuggestion = findClosestSuggestion(opLiteral.value, Array.from(EXPR_ALLOWED_CONDITION_OPERATORS))
          addIssue({
            startOffset: baseOffset + ref.openParenOffset + 1 + opLiteral.startOffset,
            endOffset: baseOffset + ref.openParenOffset + 1 + opLiteral.endOffset,
            message: withSuggestion(`Operator "${opLiteral.value}" is not supported`, opSuggestion),
            severity: 'error',
          })
        }
      }
    }
    if (fnNameLower === 'agg_if') {
      const aggArg = args[3]
      const aggLiteral = aggArg ? extractQuotedLiteralFromSegment(aggArg) : null
      if (aggLiteral) {
        const aggLower = aggLiteral.value.trim().toLowerCase()
        if (aggLower && !EXPR_ALLOWED_AGG_VALUES.has(aggLower)) {
          const aggSuggestion = findClosestSuggestion(aggLiteral.value, Array.from(EXPR_ALLOWED_AGG_VALUES))
          addIssue({
            startOffset: baseOffset + ref.openParenOffset + 1 + aggLiteral.startOffset,
            endOffset: baseOffset + ref.openParenOffset + 1 + aggLiteral.endOffset,
            message: withSuggestion(`Aggregate "${aggLiteral.value}" is not supported`, aggSuggestion),
            severity: 'error',
          })
        }
      }
      const opArg = args[4]
      const opLiteral = opArg ? extractQuotedLiteralFromSegment(opArg) : null
      if (opLiteral) {
        const opLower = opLiteral.value.trim().toLowerCase()
        if (opLower && !EXPR_ALLOWED_CONDITION_OPERATORS.has(opLower)) {
          const opSuggestion = findClosestSuggestion(opLiteral.value, Array.from(EXPR_ALLOWED_CONDITION_OPERATORS))
          addIssue({
            startOffset: baseOffset + ref.openParenOffset + 1 + opLiteral.startOffset,
            endOffset: baseOffset + ref.openParenOffset + 1 + opLiteral.endOffset,
            message: withSuggestion(`Operator "${opLiteral.value}" is not supported`, opSuggestion),
            severity: 'error',
          })
        }
      }
    }
    if (fnNameLower === 'agg' || fnNameLower === 'running_all') {
      const aggArg = args[1]
      const aggLiteral = aggArg ? extractQuotedLiteralFromSegment(aggArg) : null
      if (aggLiteral) {
        const aggLower = aggLiteral.value.trim().toLowerCase()
        if (aggLower && !EXPR_ALLOWED_AGG_VALUES.has(aggLower)) {
          const aggSuggestion = findClosestSuggestion(aggLiteral.value, Array.from(EXPR_ALLOWED_AGG_VALUES))
          addIssue({
            startOffset: baseOffset + ref.openParenOffset + 1 + aggLiteral.startOffset,
            endOffset: baseOffset + ref.openParenOffset + 1 + aggLiteral.endOffset,
            message: withSuggestion(`Aggregate "${aggLiteral.value}" is not supported`, aggSuggestion),
            severity: 'error',
          })
        }
      }
    }
    if (fnNameLower === 'rolling' || fnNameLower === 'rolling_all') {
      const aggArg = args[2]
      const aggLiteral = aggArg ? extractQuotedLiteralFromSegment(aggArg) : null
      if (aggLiteral) {
        const aggLower = aggLiteral.value.trim().toLowerCase()
        if (aggLower && !EXPR_ALLOWED_AGG_VALUES.has(aggLower)) {
          const aggSuggestion = findClosestSuggestion(aggLiteral.value, Array.from(EXPR_ALLOWED_AGG_VALUES))
          addIssue({
            startOffset: baseOffset + ref.openParenOffset + 1 + aggLiteral.startOffset,
            endOffset: baseOffset + ref.openParenOffset + 1 + aggLiteral.endOffset,
            message: withSuggestion(`Aggregate "${aggLiteral.value}" is not supported`, aggSuggestion),
            severity: 'error',
          })
        }
      }
    }
  })

  if (validationContext.allowedFieldNames.size || validationContext.allowedFieldNamesLower.size) {
    const pathMatcher = /\bpath\s*=\s*'((?:[^'\\]|\\.)*)'/g
    let pathMatch = pathMatcher.exec(source)
    while (pathMatch) {
      const raw = String(pathMatch[1] || '')
      const full = String(pathMatch[0] || '')
      const quoteOffset = full.indexOf("'")
      if (quoteOffset >= 0) {
        markUnknownField(
          decodeSingleQuotedLiteral(raw),
          pathMatch.index + quoteOffset + 1,
          pathMatch.index + quoteOffset + 1 + raw.length,
          'obj(path=...)'
        )
      }
      pathMatch = pathMatcher.exec(source)
    }
  }

  const aggMatcher = /\bagg\s*=\s*'((?:[^'\\]|\\.)*)'/g
  let aggMatch = aggMatcher.exec(source)
  while (aggMatch) {
    const raw = decodeSingleQuotedLiteral(String(aggMatch[1] || ''))
    const full = String(aggMatch[0] || '')
    const quoteOffset = full.indexOf("'")
    const aggLower = raw.trim().toLowerCase()
    if (aggLower && !EXPR_ALLOWED_AGG_VALUES.has(aggLower) && quoteOffset >= 0) {
      const aggSuggestion = findClosestSuggestion(raw, Array.from(EXPR_ALLOWED_AGG_VALUES))
      addIssue({
        startOffset: baseOffset + aggMatch.index + quoteOffset + 1,
        endOffset: baseOffset + aggMatch.index + quoteOffset + 1 + String(aggMatch[1] || '').length,
        message: withSuggestion(`Aggregate "${raw}" is not supported`, aggSuggestion),
        severity: 'error',
      })
    }
    aggMatch = aggMatcher.exec(source)
  }

  return issues
}

function validateExpressionSyntax(
  expression: string,
  baseOffset = 0,
  options?: { requireEqualsPrefix?: boolean; validationContext?: ExpressionValidationContext }
): ExpressionValidationIssue[] {
  const issues: ExpressionValidationIssue[] = []
  const source = String(expression || '')
  const trimmed = source.trim()
  const requireEqualsPrefix = options?.requireEqualsPrefix ?? true
  const validationContext = options?.validationContext || getExpressionValidationContext()

  if (!trimmed) return issues
  if (requireEqualsPrefix && !trimmed.startsWith('=')) {
    issues.push({
      startOffset: baseOffset,
      endOffset: baseOffset + Math.max(1, Math.min(source.length, 2)),
      message: 'Expression should start with "="',
      severity: 'warning',
    })
  }
  if (trimmed === '=') {
    issues.push({
      startOffset: baseOffset,
      endOffset: baseOffset + Math.max(1, source.length),
      message: 'Expression is empty',
      severity: 'error',
    })
    return issues
  }

  const stack: Array<{ ch: string; offset: number }> = []
  let quote: '"' | "'" | null = null
  let escaped = false

  for (let i = 0; i < source.length; i += 1) {
    const ch = source[i]
    if (quote) {
      if (escaped) {
        escaped = false
        continue
      }
      if (ch === '\\') {
        escaped = true
        continue
      }
      if (ch === quote) {
        quote = null
      }
      continue
    }

    if (ch === '"' || ch === "'") {
      quote = ch
      continue
    }
    if (ch === '(' || ch === '[' || ch === '{') {
      stack.push({ ch, offset: i })
      continue
    }
    if (ch === ')' || ch === ']' || ch === '}') {
      const expectedOpen = ch === ')' ? '(' : ch === ']' ? '[' : '{'
      const top = stack[stack.length - 1]
      if (!top || top.ch !== expectedOpen) {
        issues.push({
          startOffset: baseOffset + i,
          endOffset: baseOffset + i + 1,
          message: `Unexpected closing "${ch}". Check bracket order or remove this "${ch}".`,
          severity: 'error',
        })
      } else {
        stack.pop()
      }
    }
  }

  if (quote) {
    issues.push({
      startOffset: baseOffset + source.length - 1,
      endOffset: baseOffset + source.length,
      message: `Unclosed quoted string. Add closing ${quote}.`,
      severity: 'error',
    })
  }

  while (stack.length > 0) {
    const unclosed = stack.pop()!
    const expectedClose = unclosed.ch === '(' ? ')' : unclosed.ch === '[' ? ']' : '}'
    issues.push({
      startOffset: baseOffset + unclosed.offset,
      endOffset: baseOffset + unclosed.offset + 1,
      message: `Missing closing "${expectedClose}". Add "${expectedClose}" to complete this block.`,
      severity: 'error',
    })
  }

  issues.push(...validateExpressionSemantics(source, baseOffset, validationContext))

  return issues
}

function toMonacoMarkers(
  monaco: Monaco,
  model: any,
  issues: ExpressionValidationIssue[],
) {
  const markerSeverity =
    (monaco as any)?.MarkerSeverity
    || (monaco as any)?.editor?.MarkerSeverity
    || {}
  const markerErrorSeverity = markerSeverity?.Error ?? 8
  const markerWarningSeverity = markerSeverity?.Warning ?? 4

  return issues.map((issue) => {
    const safeStart = Math.max(0, issue.startOffset)
    const safeEnd = Math.max(safeStart + 1, issue.endOffset)
    const start = model.getPositionAt(safeStart)
    const end = model.getPositionAt(safeEnd)
    return {
      startLineNumber: start.lineNumber,
      startColumn: start.column,
      endLineNumber: end.lineNumber,
      endColumn: end.column,
      message: issue.message,
      severity: issue.severity === 'error'
        ? markerErrorSeverity
        : markerWarningSeverity,
    }
  })
}

function toMonacoDecorations(
  monaco: Monaco,
  model: any,
  issues: ExpressionValidationIssue[],
) {
  const minimapInlinePosition = (monaco as any)?.editor?.MinimapPosition?.Inline
  const overviewRightLane = (monaco as any)?.editor?.OverviewRulerLane?.Right
  return issues.map((issue) => {
    const safeStart = Math.max(0, issue.startOffset)
    const safeEnd = Math.max(safeStart + 1, issue.endOffset)
    const start = model.getPositionAt(safeStart)
    const end = model.getPositionAt(safeEnd)
    const severityLabel = issue.severity === 'error' ? 'Error' : 'Warning'
    return {
      range: new monaco.Range(start.lineNumber, start.column, end.lineNumber, end.column),
      options: {
        className: issue.severity === 'error' ? EXPR_RANGE_ERROR_CLASS : EXPR_RANGE_WARNING_CLASS,
        inlineClassName: issue.severity === 'error' ? EXPR_INLINE_ERROR_CLASS : EXPR_INLINE_WARNING_CLASS,
        inlineClassNameAffectsLetterSpacing: true,
        glyphMarginClassName: issue.severity === 'error' ? EXPR_GLYPH_ERROR_CLASS : EXPR_GLYPH_WARNING_CLASS,
        glyphMarginHoverMessage: [{ value: `${severityLabel}: ${issue.message}` }],
        hoverMessage: [{ value: `${severityLabel}: ${issue.message}` }],
        ...(minimapInlinePosition !== undefined
          ? {
            minimap: {
              color: issue.severity === 'error' ? '#ef4444' : '#f59e0b',
              position: minimapInlinePosition,
            },
          }
          : {}),
        ...(overviewRightLane !== undefined
          ? {
            overviewRuler: {
              color: issue.severity === 'error' ? '#ef4444' : '#f59e0b',
              position: overviewRightLane,
            },
          }
          : {}),
      },
    }
  })
}

function applyValidationDecorations(
  editor: any,
  monaco: Monaco,
  model: any,
  issues: ExpressionValidationIssue[],
): void {
  const prevDecorationIds = editorValidationDecorations.get(editor) || []
  const nextDecorationIds = editor.deltaDecorations(
    prevDecorationIds,
    toMonacoDecorations(monaco, model, issues),
  )
  editorValidationDecorations.set(editor, nextDecorationIds)
}

function clearValidationDecorations(editor: any): void {
  const prevDecorationIds = editorValidationDecorations.get(editor) || []
  if (prevDecorationIds.length > 0) {
    editor.deltaDecorations(prevDecorationIds, [])
  }
  editorValidationDecorations.delete(editor)
}

function attachExpressionValidation(editor: any, monaco: Monaco): void {
  const validate = () => {
    const model = editor.getModel()
    if (!model) return
    const text = String(model.getValue() || '')
    const issues = validateExpressionSyntax(text, 0, { requireEqualsPrefix: true })
    modelValidationIssues.set(model, issues)
    monaco.editor.setModelMarkers(model, EXPR_VALIDATION_OWNER, toMonacoMarkers(monaco, model, issues))
    applyValidationDecorations(editor, monaco, model, issues)
  }
  validate()
  editor.focus()
  editor.onDidChangeModelContent(validate)
  const mouseDisposable = editor.onMouseDown((event: any) => {
    const model = editor.getModel()
    const pos = event?.target?.position
    if (!model || !pos) return
    const offset = Number(model.getOffsetAt(pos) || 0)
    const quickFix = findIssueQuickFixAtOffset(model, offset)
    if (!quickFix) return
    modelSuggestIntent.set(model, 'issue_click')
    editor.setPosition(pos)
    editor.trigger('mouse', 'editor.action.triggerSuggest', {})
  })
  editor.onDidDispose(() => {
    mouseDisposable.dispose()
    clearValidationDecorations(editor)
    const model = editor.getModel()
    if (!model) return
    modelValidationIssues.delete(model)
    modelSuggestIntent.delete(model)
    monaco.editor.setModelMarkers(model, EXPR_VALIDATION_OWNER, [])
  })
}

function attachJsonTemplateExpressionValidation(editor: any, monaco: Monaco): void {
  const validate = () => {
    const model = editor.getModel()
    if (!model) return
    const text = String(model.getValue() || '')
    const jsonIssues = validateJsonTemplateSyntax(text)
    const ranges = extractExpressionStringRanges(text)
    const expressionIssues = ranges.flatMap((entry) =>
      validateExpressionSyntax(entry.value, entry.startOffset, { requireEqualsPrefix: false })
    )
    const issues = [...jsonIssues, ...expressionIssues]
    modelValidationIssues.set(model, issues)
    monaco.editor.setModelMarkers(model, JSON_TEMPLATE_VALIDATION_OWNER, toMonacoMarkers(monaco, model, issues))
    applyValidationDecorations(editor, monaco, model, issues)
  }
  validate()
  editor.focus()
  editor.onDidChangeModelContent(validate)
  const mouseDisposable = editor.onMouseDown((event: any) => {
    const model = editor.getModel()
    const pos = event?.target?.position
    if (!model || !pos) return
    const offset = Number(model.getOffsetAt(pos) || 0)
    const quickFix = findIssueQuickFixAtOffset(model, offset)
    if (!quickFix) return
    modelSuggestIntent.set(model, 'issue_click')
    editor.setPosition(pos)
    editor.trigger('mouse', 'editor.action.triggerSuggest', {})
  })
  editor.onDidDispose(() => {
    mouseDisposable.dispose()
    clearValidationDecorations(editor)
    const model = editor.getModel()
    if (!model) return
    modelValidationIssues.delete(model)
    modelSuggestIntent.delete(model)
    monaco.editor.setModelMarkers(model, JSON_TEMPLATE_VALIDATION_OWNER, [])
  })
}

function createCustomFieldSpec(seed?: Partial<CustomFieldSpec>): CustomFieldSpec {
  return {
    id: seed?.id || `cf_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
    name: seed?.name || '',
    mode: seed?.mode || 'value',
    singleValueOutput: seed?.singleValueOutput || 'json',
    expression: seed?.expression || '',
    jsonTemplate: seed?.jsonTemplate || '{\n  "value": "=field(\'id\')"\n}',
    enabled: seed?.enabled ?? true,
  }
}

function cloneCustomFieldSpecs(items: CustomFieldSpec[]): CustomFieldSpec[] {
  return (items || []).map((item) => ({
    ...item,
  }))
}

function createOracleColumnMappingSpec(seed?: Partial<OracleColumnMappingSpec>): OracleColumnMappingSpec {
  return {
    id: seed?.id || `orm_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
    source: String(seed?.source || '').trim(),
    destination: String(seed?.destination || '').trim(),
    enabled: seed?.enabled ?? true,
  }
}

function createLmdbStudioDraft(seed?: Partial<LmdbStudioDraft>): LmdbStudioDraft {
  const valueFormatRaw = String(seed?.value_format || 'auto').trim().toLowerCase()
  const valueFormat: 'auto' | 'json' | 'text' | 'base64' = (
    valueFormatRaw === 'json'
      ? 'json'
      : valueFormatRaw === 'text'
        ? 'text'
        : valueFormatRaw === 'base64'
          ? 'base64'
          : 'auto'
  )
  const rawLimit = Number(seed?.limit ?? 1000)
  // limit = 0 means no cap (read all matching LMDB records).
  const limit = Number.isFinite(rawLimit) ? Math.max(0, Math.floor(rawLimit)) : 1000
  return {
    env_path: String(seed?.env_path || '').trim(),
    db_name: String(seed?.db_name || '').trim(),
    key_prefix: String(seed?.key_prefix || '').trim(),
    start_key: String(seed?.start_key || '').trim(),
    end_key: String(seed?.end_key || '').trim(),
    key_contains: String(seed?.key_contains || '').trim(),
    value_contains: String(seed?.value_contains || '').trim(),
    value_format: valueFormat,
    flatten_json_values: seed?.flatten_json_values ?? true,
    expand_profile_documents: parseBoolLike(seed?.expand_profile_documents, true),
    include_entity_meta: parseBoolLike(seed?.include_entity_meta, false),
    limit,
  }
}

function parseBoolLike(value: unknown, defaultValue = false): boolean {
  if (typeof value === 'boolean') return value
  if (typeof value === 'number') return value !== 0
  if (typeof value === 'string') {
    const norm = value.trim().toLowerCase()
    if (['1', 'true', 'yes', 'y', 'on'].includes(norm)) return true
    if (['0', 'false', 'no', 'n', 'off'].includes(norm)) return false
  }
  return defaultValue
}

function normalizeSingleValueOutput(value: unknown): SingleValueOutputMode {
  const text = String(value || '').trim().toLowerCase()
  if (['plain_text', 'text', 'plain', 'string', 'str'].includes(text)) return 'plain_text'
  return 'json'
}

function toPreviewCellText(value: unknown): string {
  if (value === null || value === undefined) return ''
  if (typeof value === 'string') return value
  if (typeof value === 'number' || typeof value === 'boolean') return String(value)
  try {
    return JSON.stringify(value)
  } catch {
    return String(value)
  }
}

function toPreviewJsonText(value: unknown): string {
  try {
    return JSON.stringify(value ?? null, null, 2)
  } catch {
    return JSON.stringify(String(value ?? ''), null, 2)
  }
}

function normalizeGatewayProtocol(value: unknown): GatewayProtocol {
  const text = String(value || 'rest').trim().toLowerCase()
  if (['graphql', 'websocket', 'soap', 'tcp'].includes(text)) return text as GatewayProtocol
  return 'rest'
}

function normalizeGatewayAuthType(value: unknown): GatewayAuthType {
  const text = String(value || 'none').trim().toLowerCase()
  if (text === 'bearer' || text === 'jwt') return text
  return 'none'
}

function normalizeGatewayInputLocation(value: unknown): GatewayInputLocation {
  const text = String(value || 'query').trim().toLowerCase()
  if (text === 'path' || text === 'header' || text === 'body') return text
  return 'query'
}

function normalizeGatewayInputDataType(value: unknown): GatewayInputDataType {
  const text = String(value || 'string').trim().toLowerCase()
  if (text === 'number' || text === 'integer' || text === 'boolean' || text === 'json') return text
  return 'string'
}

function gatewayJsonText(value: unknown, fallback: Record<string, unknown> = {}): string {
  if (typeof value === 'string') {
    const trimmed = value.trim()
    if (!trimmed) return JSON.stringify(fallback, null, 2)
    try {
      return JSON.stringify(JSON.parse(trimmed), null, 2)
    } catch {
      return trimmed
    }
  }
  if (value && typeof value === 'object') return toPreviewJsonText(value)
  return JSON.stringify(fallback, null, 2)
}

function createGatewayInputParameter(seed?: Partial<GatewayInputParameter> & Record<string, unknown>): GatewayInputParameter {
  const stableId = String(seed?.id || '').trim() || `param_${Date.now()}_${Math.random().toString(16).slice(2)}`
  const sourceField = String(seed?.source_field || seed?.filter_field || seed?.field || '').trim()
  const name = String(seed?.name || '').trim() || gatewayLeafNameFromField(sourceField)
  return {
    id: stableId,
    name,
    source_field: sourceField,
    operator: String(seed?.operator || 'equals').trim().toLowerCase() || 'equals',
    location: normalizeGatewayInputLocation(seed?.location),
    required: parseBoolLike(seed?.required, false),
    data_type: normalizeGatewayInputDataType(seed?.data_type || seed?.type),
    default_value: String(seed?.default_value ?? seed?.default ?? ''),
    description: String(seed?.description || ''),
  }
}

function parseGatewayInputParameters(value: unknown): GatewayInputParameter[] {
  const raw = Array.isArray(value) ? value : []
  return raw
    .map((item) => createGatewayInputParameter((item && typeof item === 'object' ? item : {}) as Record<string, unknown>))
    .filter((item) => item.name || item.source_field || item.description || item.default_value)
}

function gatewayFieldSourcePath(field: string): string {
  const text = String(field || '').trim()
  if (!text) return ''
  if (text.includes(':')) return text.split(':').slice(1).join(':').trim()
  if (text.includes('=')) return text.split('=').slice(1).join('=').trim()
  return text
}

function gatewayLeafNameFromField(field: string): string {
  const sourcePath = gatewayFieldSourcePath(field)
  const cleaned = sourcePath.replace(/\[\]/g, '').replace(/\[\d+\]/g, '')
  const parts = cleaned.split('.').map((item) => item.trim()).filter(Boolean)
  return parts[parts.length - 1] || cleaned || ''
}

function inferGatewaySourceFieldForParameter(name: string, outputFields: string[] = []): string {
  const wanted = String(name || '').trim().toLowerCase()
  if (!wanted) return ''
  const exact = outputFields.find((field) => gatewayFieldSourcePath(field).toLowerCase() === wanted)
  if (exact) return gatewayFieldSourcePath(exact)
  const suffix = outputFields.find((field) => gatewayLeafNameFromField(field).toLowerCase() === wanted)
  return suffix ? gatewayFieldSourcePath(suffix) : ''
}

function gatewayInputParametersToPayload(parameters: GatewayInputParameter[], outputFields: string[] = []): Array<Record<string, unknown>> {
  return (parameters || [])
    .map((item) => {
      const sourceField = String(item.source_field || inferGatewaySourceFieldForParameter(item.name, outputFields)).trim()
      const name = String(item.name || gatewayLeafNameFromField(sourceField)).trim()
      return {
        name,
        source_field: sourceField,
        operator: String(item.operator || 'equals').trim().toLowerCase() || 'equals',
        location: normalizeGatewayInputLocation(item.location),
        required: Boolean(item.required),
        data_type: normalizeGatewayInputDataType(item.data_type),
        default_value: String(item.default_value ?? ''),
        description: String(item.description || '').trim(),
      }
    })
    .filter((item) => item.name)
}

function createGatewayStudioDraft(seed?: Record<string, unknown>): GatewayStudioDraft {
  const cfg = seed || {}
  const responseLimit = Number(cfg.response_limit ?? 1000)
  const rateRequests = Number(cfg.rate_limit_requests ?? 0)
  const rateWindow = Number(cfg.rate_limit_window_seconds ?? 60)
  const requestMapping = (() => {
    const raw = cfg.request_mapping
    if (raw && typeof raw === 'object' && !Array.isArray(raw)) return raw as Record<string, unknown>
    if (typeof raw === 'string' && raw.trim()) {
      try {
        const parsed = JSON.parse(raw)
        if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) return parsed as Record<string, unknown>
      } catch {
        return {}
      }
    }
    return {}
  })()
  const responseMapping = (() => {
    const raw = cfg.response_mapping
    if (raw && typeof raw === 'object' && !Array.isArray(raw)) return raw as Record<string, unknown>
    if (typeof raw === 'string' && raw.trim()) {
      try {
        const parsed = JSON.parse(raw)
        if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) return parsed as Record<string, unknown>
      } catch {
        return {}
      }
    }
    return {}
  })()
  return {
    route_id: String(cfg.route_id || cfg.id || '').trim(),
    gateway_name: String(cfg.gateway_name || cfg.name || 'Gateway Route'),
    enabled: parseBoolLike(cfg.enabled, true),
    protocol: normalizeGatewayProtocol(cfg.protocol),
    api_version: String(cfg.api_version || cfg.version || 'v1').trim().replace(/^\/+|\/+$/g, '') || 'v1',
    route_method: String(cfg.route_method || cfg.method || 'GET').trim().toUpperCase() || 'GET',
    route_path: String(cfg.route_path || cfg.path || '/gateway').trim() || '/gateway',
    source_node_id: String(cfg.source_node_id || '').trim(),
    trigger_node_ids: parseStringList(cfg.trigger_node_ids || requestMapping.trigger_node_ids || requestMapping.execution_node_ids || requestMapping.node_ids),
    source_config_text: gatewayJsonText(cfg.source_config, {}),
    request_mapping_text: gatewayJsonText(cfg.request_mapping, {}),
    input_parameters: parseGatewayInputParameters(cfg.input_parameters || requestMapping.input_parameters || requestMapping.parameters),
    response_mapping_text: gatewayJsonText(cfg.response_mapping, { limit: Number.isFinite(responseLimit) ? responseLimit : 1000 }),
    output_fields: parseStringList(cfg.output_fields || responseMapping.output_fields),
    response_limit: Number.isFinite(responseLimit) ? Math.max(1, Math.floor(responseLimit)) : 1000,
    graphql_field: String(cfg.graphql_field || responseMapping.graphql_field || 'result').trim() || 'result',
    standard_response: parseBoolLike(cfg.standard_response, true),
    auth_type: normalizeGatewayAuthType(cfg.auth_type),
    auth_token: String(cfg.auth_token || ''),
    jwt_secret: String(cfg.jwt_secret || ''),
    jwt_issuer: String(cfg.jwt_issuer || ''),
    jwt_audience: String(cfg.jwt_audience || ''),
    rbac_roles: String(cfg.rbac_roles || ''),
    rate_limit_requests: Number.isFinite(rateRequests) ? Math.max(0, Math.floor(rateRequests)) : 0,
    rate_limit_window_seconds: Number.isFinite(rateWindow) ? Math.max(1, Math.floor(rateWindow)) : 60,
    audit_enabled: parseBoolLike(cfg.audit_enabled, true),
    logging_enabled: parseBoolLike(cfg.logging_enabled, true),
  }
}

function gatewayDraftToNodeConfig(draft: GatewayStudioDraft): Record<string, unknown> {
  return {
    route_id: draft.route_id,
    gateway_name: draft.gateway_name,
    enabled: draft.enabled,
    protocol: draft.protocol,
    api_version: draft.api_version || 'v1',
    route_method: draft.route_method || 'GET',
    route_path: draft.route_path || '/gateway',
    source_node_id: draft.source_node_id,
    trigger_node_ids: draft.trigger_node_ids || [],
    source_config: draft.source_config_text || '{}',
    request_mapping: draft.request_mapping_text || '{}',
    input_parameters: gatewayInputParametersToPayload(draft.input_parameters, draft.output_fields),
    response_mapping: draft.response_mapping_text || '{}',
    output_fields: draft.output_fields || [],
    response_limit: draft.response_limit || 1000,
    graphql_field: draft.graphql_field || 'result',
    standard_response: draft.standard_response,
    auth_type: draft.auth_type,
    auth_token: draft.auth_token,
    jwt_secret: draft.jwt_secret,
    jwt_issuer: draft.jwt_issuer,
    jwt_audience: draft.jwt_audience,
    rbac_roles: draft.rbac_roles,
    rate_limit_requests: draft.rate_limit_requests || 0,
    rate_limit_window_seconds: draft.rate_limit_window_seconds || 60,
    audit_enabled: draft.audit_enabled,
    logging_enabled: draft.logging_enabled,
  }
}

function gatewayDraftRuntimePath(draft: GatewayStudioDraft): string {
  const protocol = normalizeGatewayProtocol(draft.protocol)
  const apiVersion = String(draft.api_version || 'v1').replace(/^\/+|\/+$/g, '') || 'v1'
  const routePath = String(draft.route_path || '/gateway').startsWith('/')
    ? String(draft.route_path || '/gateway')
    : `/${String(draft.route_path || 'gateway')}`
  const protocolPrefix = protocol === 'rest' ? '' : `/${protocol}`
  return `/gw${protocolPrefix}/${apiVersion}${routePath}`
}

function createGatewayTestKeyValue(seed?: Partial<GatewayTestKeyValue>): GatewayTestKeyValue {
  return {
    id: String(seed?.id || `kv_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`),
    key: String(seed?.key || ''),
    value: String(seed?.value ?? ''),
    enabled: parseBoolLike(seed?.enabled, true),
  }
}

function parseGatewayTestKeyValues(value: unknown): GatewayTestKeyValue[] {
  if (Array.isArray(value)) {
    return value
      .map((item) => {
        if (!item || typeof item !== 'object') return null
        const row = item as Record<string, unknown>
        const key = String(row.key || row.name || '').trim()
        if (!key && !String(row.value ?? '').trim()) return null
        return createGatewayTestKeyValue({
          id: String(row.id || ''),
          key,
          value: String(row.value ?? row.default_value ?? ''),
          enabled: parseBoolLike(row.enabled, true),
        })
      })
      .filter((item): item is GatewayTestKeyValue => Boolean(item))
  }
  if (value && typeof value === 'object') {
    return Object.entries(value as Record<string, unknown>).map(([key, raw]) => (
      createGatewayTestKeyValue({ key, value: String(raw ?? '') })
    ))
  }
  return []
}

function normalizeGatewayTestBodyType(value: unknown): GatewayTestBodyType {
  const normalized = String(value || '').trim().toLowerCase()
  if (normalized === 'json' || normalized === 'graphql' || normalized === 'xml' || normalized === 'text') return normalized
  return 'none'
}

function gatewayDefaultMethodForProtocol(protocol: GatewayProtocol, fallback?: string): string {
  const normalized = normalizeGatewayProtocol(protocol)
  if (normalized === 'graphql' || normalized === 'soap' || normalized === 'tcp') return 'POST'
  return String(fallback || 'GET').trim().toUpperCase() || 'GET'
}

function gatewayTestPathForProtocol(path: string, protocol: GatewayProtocol): string {
  const normalized = normalizeGatewayProtocol(protocol)
  const protocolPrefix = normalized === 'rest' ? '' : `/${normalized}`
  const text = String(path || '').trim()
  const safePath = text.startsWith('/') ? text : `/${text || 'gw/v1/gateway'}`
  const match = safePath.match(/^\/gw(?:\/(?:graphql|soap|tcp))?\/([^/]+)(\/.*)?$/i)
  if (match) {
    const version = String(match[1] || 'v1').replace(/^\/+|\/+$/g, '') || 'v1'
    const routePath = String(match[2] || '/gateway').startsWith('/') ? String(match[2] || '/gateway') : `/${String(match[2] || 'gateway')}`
    return `/gw${protocolPrefix}/${version}${routePath}`
  }
  return `/gw${protocolPrefix}/v1/gateway`
}

function gatewayDefaultHeaderRows(bodyType: GatewayTestBodyType): GatewayTestKeyValue[] {
  if (bodyType === 'json' || bodyType === 'graphql') {
    return [
      createGatewayTestKeyValue({ key: 'Content-Type', value: 'application/json' }),
      createGatewayTestKeyValue({ key: 'Accept', value: 'application/json' }),
    ]
  }
  if (bodyType === 'xml') {
    return [
      createGatewayTestKeyValue({ key: 'Content-Type', value: 'text/xml; charset=utf-8' }),
      createGatewayTestKeyValue({ key: 'Accept', value: 'text/xml, application/xml, application/json' }),
      createGatewayTestKeyValue({ key: 'SOAPAction', value: '' }),
    ]
  }
  if (bodyType === 'text') {
    return [
      createGatewayTestKeyValue({ key: 'Content-Type', value: 'text/plain; charset=utf-8' }),
      createGatewayTestKeyValue({ key: 'Accept', value: 'application/json' }),
    ]
  }
  return [createGatewayTestKeyValue({ key: 'Accept', value: 'application/json' })]
}

function gatewayHeadersForBodyType(headers: GatewayTestKeyValue[], bodyType: GatewayTestBodyType): GatewayTestKeyValue[] {
  const defaults = gatewayDefaultHeaderRows(bodyType)
  if (!headers || headers.length === 0) return defaults
  const defaultByKey = new Map(defaults.map((item) => [item.key.toLowerCase(), item.value]))
  const seen = new Set<string>()
  const updated = headers.map((item) => {
    const key = String(item.key || '').trim()
    const lower = key.toLowerCase()
    seen.add(lower)
    if (defaultByKey.has(lower)) {
      return { ...item, value: String(defaultByKey.get(lower) ?? item.value), enabled: true }
    }
    return item
  })
  defaults.forEach((item) => {
    const lower = item.key.toLowerCase()
    if (!seen.has(lower)) updated.push(item)
  })
  return updated
}

function gatewayTestHeaderPresetValue(key: string, bodyType: GatewayTestBodyType): string {
  const normalized = String(key || '').trim().toLowerCase()
  if (normalized === 'content-type') {
    if (bodyType === 'xml') return 'text/xml; charset=utf-8'
    if (bodyType === 'text') return 'text/plain; charset=utf-8'
    return 'application/json'
  }
  if (normalized === 'accept') {
    if (bodyType === 'xml') return 'text/xml, application/xml, application/json'
    return 'application/json'
  }
  const preset = GATEWAY_TEST_HEADER_PRESETS.find((item) => item.key.toLowerCase() === normalized)
  return preset?.value ?? ''
}

function gatewayTestHeaderValueOptions(key: string, bodyType: GatewayTestBodyType): Array<{ value: string; label: string }> {
  const normalized = String(key || '').trim().toLowerCase()
  const values: string[] = []
  const add = (value: string) => {
    const text = String(value || '')
    if (values.includes(text)) return
    values.push(text)
  }
  const defaultValue = gatewayTestHeaderPresetValue(key, bodyType)
  if (defaultValue || normalized === 'soapaction' || normalized === 'x-api-key') add(defaultValue)
  if (normalized === 'content-type') {
    add('application/json')
    add('text/xml; charset=utf-8')
    add('application/xml')
    add('text/plain; charset=utf-8')
    add('application/x-www-form-urlencoded')
    add('multipart/form-data')
  } else if (normalized === 'accept') {
    add('application/json')
    add('text/xml, application/xml, application/json')
    add('application/xml')
    add('text/plain')
    add('*/*')
  } else if (normalized === 'authorization') {
    add('Bearer ')
    add('Basic ')
    add('ApiKey ')
  } else if (normalized === 'soapaction') {
    add('GatewayRequest')
    add('GetGatewayData')
    add('urn:framework-gateway#GatewayRequest')
  } else if (normalized === 'user-agent') {
    add('FRAMEWORK-Gateway-Tester')
    add('PostmanRuntime/7.39.0')
  } else if (normalized === 'x-request-id' || normalized === 'x-correlation-id') {
    add(`gw-test-${Date.now()}`)
  }
  return values.map((value) => ({ value, label: value || '(empty)' }))
}

function gatewayDefaultQueryRows(route: GatewayStudioDraft): GatewayTestKeyValue[] {
  return (route.input_parameters || [])
    .filter((param) => String(param.location || 'query').toLowerCase() !== 'header')
    .map((param) => createGatewayTestKeyValue({
      key: String(param.name || gatewayLeafNameFromField(param.source_field) || '').trim(),
      value: String(param.default_value ?? ''),
      enabled: true,
    }))
    .filter((item) => item.key)
}

function gatewayDefaultBodyForRoute(route: GatewayStudioDraft): { bodyType: GatewayTestBodyType; bodyText: string; headers: GatewayTestKeyValue[] } {
  const protocol = normalizeGatewayProtocol(route.protocol)
  const params = (route.input_parameters || []).filter((param) => String(param.name || '').trim())
  if (protocol === 'graphql') {
    const responseField = String(route.graphql_field || 'result').trim() || 'result'
    const variableDefs = params.map((param) => `$${param.name}: String`).join(', ')
    const argumentText = params.map((param) => `${param.name}: $${param.name}`).join(', ')
    const selectedFields = uniqueFieldNames((route.output_fields || []).map((field) => gatewayLeafNameFromField(field)).filter(Boolean)).slice(0, 6)
    const selection = selectedFields.length > 0 ? selectedFields.join('\n      ') : 'customer_account'
    const queryArgs = variableDefs ? `(${variableDefs})` : ''
    const fieldArgs = argumentText ? `(${argumentText})` : ''
    return {
      bodyType: 'graphql',
      bodyText: `query${queryArgs} {\n  ${responseField}${fieldArgs} {\n      ${selection}\n  }\n}`,
      headers: gatewayDefaultHeaderRows('graphql'),
    }
  }
  if (protocol === 'soap') {
    const inputXml = params.map((param) => {
      const name = String(param.name || '').trim()
      const value = String(param.default_value ?? '')
      return `      <gw:${name}>${value}</gw:${name}>`
    }).join('\n')
    return {
      bodyType: 'xml',
      bodyText: [
        '<?xml version="1.0" encoding="UTF-8"?>',
        '<soapenv:Envelope xmlns:soapenv="http://schemas.xmlsoap.org/soap/envelope/" xmlns:gw="urn:framework-gateway">',
        '  <soapenv:Header/>',
        '  <soapenv:Body>',
        '    <gw:GatewayRequest>',
        inputXml || '      <gw:limit>10</gw:limit>',
        '    </gw:GatewayRequest>',
        '  </soapenv:Body>',
        '</soapenv:Envelope>',
      ].join('\n'),
      headers: gatewayDefaultHeaderRows('xml'),
    }
  }
  return { bodyType: 'none', bodyText: '', headers: [] }
}

function createGatewayTestConfig(
  seed?: Partial<GatewayTestConfig> & Record<string, unknown>,
  route?: GatewayStudioDraft,
): GatewayTestConfig {
  const routeDraft = route || createGatewayStudioDraft()
  const defaults = gatewayDefaultBodyForRoute(routeDraft)
  const now = new Date().toISOString()
  const bodyType = normalizeGatewayTestBodyType(seed?.body_type || defaults.bodyType)
  const queryRows = parseGatewayTestKeyValues(seed?.query_params)
  const headerRows = parseGatewayTestKeyValues(seed?.headers)
  return {
    id: String(seed?.id || `test_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`),
    name: String(seed?.name || `${routeDraft.gateway_name || 'Gateway Route'} test`),
    route_id: String(seed?.route_id || routeDraft.route_id || ''),
    protocol: normalizeGatewayProtocol(seed?.protocol || routeDraft.protocol),
    method: gatewayDefaultMethodForProtocol(normalizeGatewayProtocol(seed?.protocol || routeDraft.protocol), String(seed?.method || routeDraft.route_method || 'GET')),
    path: String(seed?.path || gatewayDraftRuntimePath(routeDraft)),
    query_params: queryRows.length > 0 ? queryRows : gatewayDefaultQueryRows(routeDraft),
    headers: headerRows.length > 0 ? headerRows : (bodyType === defaults.bodyType ? defaults.headers : gatewayDefaultHeaderRows(bodyType)),
    body_type: bodyType,
    body_text: String(seed?.body_text ?? defaults.bodyText),
    created_at: String(seed?.created_at || now),
    updated_at: String(seed?.updated_at || now),
  }
}

function parseGatewayTestConfigs(value: unknown, route?: GatewayStudioDraft): GatewayTestConfig[] {
  if (!Array.isArray(value)) return []
  return value
    .map((item) => {
      if (!item || typeof item !== 'object') return null
      return createGatewayTestConfig(item as Partial<GatewayTestConfig> & Record<string, unknown>, route)
    })
    .filter((item): item is GatewayTestConfig => Boolean(item))
}

function mergeGatewayTestConfigs(...groups: GatewayTestConfig[][]): GatewayTestConfig[] {
  const out: GatewayTestConfig[] = []
  const seen = new Set<string>()
  groups.flat().forEach((item) => {
    const id = String(item?.id || '').trim()
    if (!id || seen.has(id)) return
    seen.add(id)
    out.push(item)
  })
  return out
}

function gatewayTestConfigStorageKey(pipelineId: string, nodeId: string): string {
  return `${String(pipelineId || 'pipeline').trim() || 'pipeline'}::${String(nodeId || 'node').trim() || 'node'}`
}

function readStoredGatewayTestConfigs(pipelineId: string, nodeId: string, route?: GatewayStudioDraft): GatewayTestConfig[] {
  if (typeof window === 'undefined' || !window.localStorage || !pipelineId || !nodeId) return []
  try {
    const raw = window.localStorage.getItem(GATEWAY_TEST_CONFIG_STORAGE_KEY)
    if (!raw) return []
    const parsed = JSON.parse(raw)
    if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) return []
    const bucket = (parsed as Record<string, unknown>)[gatewayTestConfigStorageKey(pipelineId, nodeId)]
    return parseGatewayTestConfigs(bucket, route)
  } catch {
    return []
  }
}

function writeStoredGatewayTestConfigs(pipelineId: string, nodeId: string, tests: GatewayTestConfig[]): void {
  if (typeof window === 'undefined' || !window.localStorage || !pipelineId || !nodeId) return
  try {
    const raw = window.localStorage.getItem(GATEWAY_TEST_CONFIG_STORAGE_KEY)
    const parsed = raw ? JSON.parse(raw) : {}
    const store = parsed && typeof parsed === 'object' && !Array.isArray(parsed)
      ? parsed as Record<string, unknown>
      : {}
    store[gatewayTestConfigStorageKey(pipelineId, nodeId)] = tests.map(gatewayTestToPayload)
    window.localStorage.setItem(GATEWAY_TEST_CONFIG_STORAGE_KEY, JSON.stringify(store))
  } catch {
    // Local backup is best-effort; node config remains the source of truth.
  }
}

function gatewayTestToPayload(test: GatewayTestConfig): Record<string, unknown> {
  return {
    id: test.id,
    name: test.name,
    route_id: test.route_id,
    protocol: test.protocol,
    method: test.method,
    path: test.path,
    query_params: test.query_params.map((item) => ({ id: item.id, key: item.key, value: item.value, enabled: item.enabled })),
    headers: test.headers.map((item) => ({ id: item.id, key: item.key, value: item.value, enabled: item.enabled })),
    body_type: test.body_type,
    body_text: test.body_text,
    created_at: test.created_at,
    updated_at: test.updated_at,
  }
}

function gatewayTestKeyValuesToObject(rows: GatewayTestKeyValue[]): Record<string, string> {
  return (rows || []).reduce<Record<string, string>>((acc, row) => {
    const key = String(row.key || '').trim()
    if (!key || row.enabled === false) return acc
    acc[key] = String(row.value ?? '')
    return acc
  }, {})
}

function gatewayTestResponseText(value: unknown): string {
  if (value === null || value === undefined) return ''
  if (typeof value === 'string') return value
  try {
    return JSON.stringify(value, null, 2)
  } catch {
    return String(value)
  }
}

function gatewayTestResponseBodyText(result: Record<string, unknown> | null, view: GatewayTestResponseView): string {
  if (!result) return ''
  const payload = (result as any).data ?? result
  if (view === 'raw') return gatewayTestResponseText(payload)
  if (typeof payload === 'string') {
    try {
      return JSON.stringify(JSON.parse(payload), null, 2)
    } catch {
      return payload
    }
  }
  return gatewayTestResponseText(payload)
}

function gatewayTestEditorLanguage(bodyType: GatewayTestBodyType, responseView?: GatewayTestResponseView): string {
  if (responseView === 'raw') return 'plaintext'
  if (bodyType === 'graphql') return GATEWAY_GRAPHQL_LANGUAGE_ID
  if (bodyType === 'json') return 'json'
  if (bodyType === 'xml') return 'xml'
  return 'plaintext'
}

function gatewayGraphqlTextFromBody(value: string): string {
  const text = String(value || '')
  if (!text.trim()) return ''
  try {
    const parsed = JSON.parse(text)
    if (parsed && typeof parsed === 'object' && typeof (parsed as Record<string, unknown>).query === 'string') {
      return String((parsed as Record<string, unknown>).query)
    }
  } catch {
    return text
  }
  return text
}

function gatewayJsonValidationMessage(value: string): string {
  const text = String(value || '').trim()
  if (!text) return ''
  try {
    JSON.parse(text)
    return ''
  } catch (err: any) {
    return String(err?.message || 'Invalid JSON')
  }
}

function detectJsonValueKind(value: unknown): JsonTagMappingItem['kind'] {
  if (value === null || value === undefined) return 'null'
  if (Array.isArray(value)) return 'array'
  const t = typeof value
  if (t === 'string') return 'string'
  if (t === 'number') return 'number'
  if (t === 'boolean') return 'boolean'
  if (t === 'object') return 'object'
  return 'string'
}

function toJsonTagSample(value: unknown): string {
  if (value === null || value === undefined) return 'null'
  if (typeof value === 'string') {
    const trimmed = value.trim()
    return trimmed.length > 72 ? `${trimmed.slice(0, 69)}...` : trimmed
  }
  if (typeof value === 'number' || typeof value === 'boolean') return String(value)
  if (Array.isArray(value)) return `Array(${value.length})`
  if (typeof value === 'object') {
    const keys = Object.keys(value as Record<string, unknown>)
    return `Object(${keys.length})`
  }
  return String(value)
}

function escapeExprPath(path: string): string {
  return String(path || '').replace(/\\/g, '\\\\').replace(/'/g, "\\'")
}

function buildJsonTagMapping(path: string, value: unknown): JsonTagMappingItem {
  const safePath = escapeExprPath(path)
  return {
    path,
    kind: detectJsonValueKind(value),
    sample: toJsonTagSample(value),
    fieldExpr: `=field('${safePath}')`,
    valuesExpr: `=values('${safePath}')`,
    controlTag: `{{${path}}}`,
  }
}

function collectJsonTagMappings(
  value: unknown,
  basePath: string,
  out: JsonTagMappingItem[],
  seen: Set<string>,
  depth: number
): void {
  if (depth > MAX_JSON_TAG_DEPTH || out.length >= MAX_JSON_TAG_MAPPINGS) return

  if (basePath) {
    const dedupeKey = `${basePath}|${detectJsonValueKind(value)}`
    if (!seen.has(dedupeKey)) {
      seen.add(dedupeKey)
      out.push(buildJsonTagMapping(basePath, value))
      if (out.length >= MAX_JSON_TAG_MAPPINGS) return
    }
  }

  if (Array.isArray(value)) {
    if (!basePath) return
    const wildcardPath = `${basePath}[]`
    if (!seen.has(`${wildcardPath}|array`)) {
      seen.add(`${wildcardPath}|array`)
      out.push(buildJsonTagMapping(wildcardPath, value))
      if (out.length >= MAX_JSON_TAG_MAPPINGS) return
    }
    const sampleItems = value.slice(0, MAX_ARRAY_INDEX_OPTIONS)
    sampleItems.forEach((item, idx) => {
      const idxPath = `${basePath}[${idx}]`
      collectJsonTagMappings(item, idxPath, out, seen, depth + 1)
    })
    const exemplar = value.find((item) => item !== null && item !== undefined)
    if (exemplar !== undefined) {
      collectJsonTagMappings(exemplar, wildcardPath, out, seen, depth + 1)
    }
    return
  }

  if (value && typeof value === 'object') {
    Object.entries(value as Record<string, unknown>)
      .slice(0, MAX_OBJECT_KEYS_PER_LEVEL)
      .forEach(([key, child]) => {
        const nextPath = basePath ? `${basePath}.${key}` : key
        collectJsonTagMappings(child, nextPath, out, seen, depth + 1)
      })
  }
}

function buildJsonTagMappingsFromParsed(value: unknown): JsonTagMappingItem[] {
  const out: JsonTagMappingItem[] = []
  const seen = new Set<string>()
  if (value === null || value === undefined) return out
  if (Array.isArray(value)) {
    value.slice(0, MAX_ARRAY_INDEX_OPTIONS).forEach((item, idx) => {
      collectJsonTagMappings(item, `[${idx}]`, out, seen, 0)
    })
    const exemplar = value.find((item) => item !== null && item !== undefined)
    if (exemplar !== undefined) {
      collectJsonTagMappings(exemplar, '[]', out, seen, 0)
    }
    return out.slice(0, MAX_JSON_TAG_MAPPINGS)
  }
  if (value && typeof value === 'object') {
    Object.entries(value as Record<string, unknown>)
      .slice(0, MAX_OBJECT_KEYS_PER_LEVEL)
      .forEach(([key, child]) => {
        collectJsonTagMappings(child, key, out, seen, 0)
      })
    return out.slice(0, MAX_JSON_TAG_MAPPINGS)
  }
  collectJsonTagMappings(value, 'value', out, seen, 0)
  return out.slice(0, MAX_JSON_TAG_MAPPINGS)
}

function tryParseSortableNumber(value: unknown): number | null {
  if (typeof value === 'number' && Number.isFinite(value)) return value
  if (typeof value !== 'string') return null
  const trimmed = value.trim()
  if (!trimmed) return null
  if (!/^-?\d+(\.\d+)?$/.test(trimmed)) return null
  const parsed = Number(trimmed)
  return Number.isFinite(parsed) ? parsed : null
}

function applyRocksdbIncrementalTuningDefaults(
  setFlushRows: (value: number) => void,
  setFlushInterval: (value: number) => void,
  setDisableMinRows: (value: number) => void,
  setEntityLimit: (value: number) => void,
  setDisableRatio: (value: number) => void,
): void {
  setFlushRows(50000)
  setFlushInterval(10)
  setDisableMinRows(5000)
  setEntityLimit(10000)
  setDisableRatio(0.35)
}

function parseOracleColumnMappings(value: unknown): OracleColumnMappingSpec[] {
  let raw: unknown = value
  if (typeof raw === 'string') {
    const text = raw.trim()
    if (!text) return []
    try {
      raw = JSON.parse(text)
    } catch {
      return []
    }
  }

  if (!Array.isArray(raw)) return []

  return raw
    .map((item) => {
      if (!item || typeof item !== 'object') return null
      const rec = item as Record<string, unknown>
      const source = String(rec.source ?? rec.from ?? '').trim()
      const destination = String(rec.destination ?? rec.to ?? '').trim()
      const enabled = parseBoolLike(rec.enabled, true)
      if (!source && !destination) return null
      return createOracleColumnMappingSpec({
        id: String(rec.id || ''),
        source,
        destination,
        enabled,
      })
    })
    .filter((item): item is OracleColumnMappingSpec => !!item)
}

function serializeOracleColumnMappings(items: OracleColumnMappingSpec[]): Array<Record<string, unknown>> {
  return items
    .map((item) => ({
      source: String(item.source || '').trim(),
      destination: String(item.destination || '').trim(),
      enabled: Boolean(item.enabled),
    }))
    .filter((item) => item.source || item.destination)
}

function parseCustomFieldSpecs(value: unknown): CustomFieldSpec[] {
  let raw = value
  if (typeof raw === 'string') {
    const text = raw.trim()
    if (!text) return []
    try {
      raw = JSON.parse(text)
    } catch {
      return []
    }
  }
  if (!Array.isArray(raw)) return []

  const out: CustomFieldSpec[] = []
  raw.forEach((item) => {
    if (!item || typeof item !== 'object') return
    const rec = item as Record<string, unknown>
    const modeRaw = String(rec.mode || rec.kind || rec.type || 'value').trim().toLowerCase()
    const mode: CustomFieldMode = modeRaw === 'json' ? 'json' : 'value'
    const rawJsonTemplate = String(rec.jsonTemplate || rec.json_template || rec.template || '')
    out.push(
      createCustomFieldSpec({
        id: String(rec.id || ''),
        name: String(rec.name || rec.field || ''),
        mode,
        singleValueOutput: normalizeSingleValueOutput(
          rec.singleValueOutput ?? rec.single_value_output ?? rec.value_output ?? rec.output_format
        ),
        expression: String(rec.expression || rec.expr || ''),
        jsonTemplate: rawJsonTemplate,
        enabled: parseBoolLike(rec.enabled, true),
      })
    )
  })
  return out.filter((item) => !isLegacyDefaultJsonObjectName(item.name))
}

function serializeCustomFieldSpecs(items: CustomFieldSpec[]): Array<Record<string, unknown>> {
  return items
    // custom_profile is reserved for the profile-engine config prefix; older
    // Expression Studio drafts used it as a default object name.
    .filter((item) => !isLegacyDefaultJsonObjectName(item.name))
    .map((item) => ({
      id: String(item.id || '').trim(),
      name: String(item.name || '').trim(),
      mode: item.mode,
      single_value_output: item.mode === 'value' ? item.singleValueOutput : 'json',
      expression: item.mode === 'value' ? String(item.expression || '') : '',
      json_template: item.mode === 'json' ? normalizeJsonTemplateForStorage(String(item.jsonTemplate || '')) : '',
      enabled: Boolean(item.enabled),
    }))
    .filter((item) => item.name)
}

function uniqueFieldNames(values: string[]): string[] {
  const out: string[] = []
  const seen = new Set<string>()
  values.forEach((raw) => {
    const name = String(raw || '').trim()
    if (!name) return
    const key = name.toLowerCase()
    if (seen.has(key)) return
    seen.add(key)
    out.push(name)
  })
  return out
}

function collectJsonTemplateKeyPaths(
  value: unknown,
  basePath: string,
  out: Set<string>,
  depth: number
): void {
  if (depth > MAX_PATH_DEPTH || out.size >= MAX_PATH_OPTIONS) return

  if (Array.isArray(value)) {
    if (!basePath) return
    out.add(basePath)
    const wildcardPath = `${basePath}[]`
    out.add(wildcardPath)
    const sampleItems = value.slice(0, MAX_ARRAY_INDEX_OPTIONS)
    sampleItems.forEach((item, idx) => {
      const idxPath = `${basePath}[${idx}]`
      out.add(idxPath)
      collectJsonTemplateKeyPaths(item, idxPath, out, depth + 1)
    })
    const exemplar = value.find((item) => item !== null && item !== undefined)
    if (exemplar !== undefined) {
      collectJsonTemplateKeyPaths(exemplar, wildcardPath, out, depth + 1)
    }
    return
  }

  if (value && typeof value === 'object') {
    const entries = Object.entries(value as Record<string, unknown>).slice(0, MAX_OBJECT_KEYS_PER_LEVEL)
    entries.forEach(([key, child]) => {
      const nextPath = basePath ? `${basePath}.${key}` : key
      out.add(nextPath)
      collectJsonTemplateKeyPaths(child, nextPath, out, depth + 1)
    })
  }
}

function extractJsonTemplateKeyPaths(jsonTemplate: string): string[] {
  const text = String(jsonTemplate || '').trim()
  if (!text) return []
  try {
    const parsed = parseJsonTemplateLikeValue(text)
    if (!parsed) throw new Error('Template parse failed')
    const out = new Set<string>()
    collectJsonTemplateKeyPaths(parsed, '', out, 0)
    return uniqueFieldNames(Array.from(out))
  } catch {
    // Best-effort fallback while user is still typing malformed JSON.
    const out = new Set<string>()
    const keyMatcher = /(?:"([^"\\]+)"|([A-Za-z_$][\w$]*))\s*:/g
    let keyMatch = keyMatcher.exec(text)
    while (keyMatch) {
      const key = String(keyMatch[1] || keyMatch[2] || '').trim()
      if (key) out.add(key)
      keyMatch = keyMatcher.exec(text)
    }
    return uniqueFieldNames(Array.from(out))
  }
}

function expressionStudioProfilePathFirstArg(expression: string): { fnName: string; pathName: string; args: string[] } | null {
  const call = parseTopLevelFunctionCallSource(stripExpressionPrefix(expression))
  if (!call || call.args.length === 0) return null
  const pathName = stripEnclosingQuotes(call.args[0])
  if (!pathName) return null
  return { fnName: String(call.name || '').trim().toLowerCase(), pathName, args: call.args }
}

function expressionStudioWindowNamesFromObjArg(objArg: string, fallback: string[] = ['1d', '7d', '30d']): string[] {
  const call = parseTopLevelFunctionCallSource(String(objArg || '').trim())
  if (!call || String(call.name || '').toLowerCase() !== 'obj') return fallback
  const windows = stripEnclosingQuotes(parseNamedObjLiteralArg(call.args, 'windows'))
  const names = windows.split(',').map((item) => item.trim()).filter(Boolean)
  return names.length > 0 ? names : fallback
}

function inferMetricGetPathSuggestionsFromExpression(expression: string): string[] {
  const text = stripExpressionPrefix(String(expression || '').trim())
  if (!text) return []
  const out = new Set<string>()
  const matcher = /metric_get\s*\(\s*(['"])(.*?)\1\s*,\s*(['"])(.*?)\3\s*\)/gi
  let match = matcher.exec(text)
  while (match) {
    const pathName = stripEnclosingQuotes(match[1] + String(match[2] || '') + match[1])
    const metricName = stripEnclosingQuotes(match[3] + String(match[4] || '') + match[3]) || 'value'
    if (pathName) out.add(`${pathName}.${metricName}`)
    match = matcher.exec(text)
  }
  return uniqueFieldNames(Array.from(out))
}

function inferProfilePathSuggestionsFromExpression(expression: string): string[] {
  const metricPathSuggestions = inferMetricGetPathSuggestionsFromExpression(expression)
  const parsed = expressionStudioProfilePathFirstArg(expression)
  if (!parsed) return metricPathSuggestions
  const { fnName, pathName, args } = parsed
  const out = new Set<string>([pathName, ...metricPathSuggestions])
  if (fnName === 'unique_velocity') {
    out.add(`${pathName}.per_min`)
    out.add(`${pathName}.per_hour`)
    out.add(`${pathName}.count`)
  } else if (fnName === 'unique_rolling' || fnName === 'unique_window') {
    expressionStudioWindowNamesFromObjArg(args[2] || '').forEach((windowName) => {
      const windowPath = `${pathName}.w_${windowName.replace(/[^A-Za-z0-9_]/g, '_')}`
      ;['count', 'sum', 'avg', 'min', 'max'].forEach((metric) => out.add(`${windowPath}.${metric}`))
    })
  } else if (fnName === 'unique_stats') {
    ;['count', 'sum', 'avg', 'min', 'max', 'std', 'stddev'].forEach((metric) => out.add(`${pathName}.${metric}`))
  } else if (fnName === 'unique_ratio' || fnName === 'unique_rate') {
    out.add(`${pathName}.ratio`)
    out.add(`${pathName}.rate`)
  } else if (fnName === 'unique_flag' || fnName.endsWith('_flag')) {
    out.add(`${pathName}.flag`)
  } else if (fnName === 'partition_zscore') {
    out.add(`${pathName}.value`)
    out.add(`${pathName}.zscore`)
  } else if (fnName === 'metric_get') {
    const metric = stripEnclosingQuotes(String(args[1] || '').trim()) || 'value'
    out.add(`${pathName}.${metric}`)
  }
  return uniqueFieldNames(Array.from(out))
}

function collectProfilePathSuggestionsFromJsonValue(value: unknown, out: Set<string>, rootName = ''): void {
  if (typeof value === 'string') {
    inferProfilePathSuggestionsFromExpression(value).forEach((pathName) => {
      out.add(pathName)
      if (rootName) out.add(`${rootName}.${pathName}`)
    })
    return
  }
  if (Array.isArray(value)) {
    value.forEach((item) => collectProfilePathSuggestionsFromJsonValue(item, out, rootName))
    return
  }
  if (value && typeof value === 'object') {
    Object.values(value as Record<string, unknown>).forEach((child) => {
      collectProfilePathSuggestionsFromJsonValue(child, out, rootName)
    })
  }
}

function buildCustomProfilePathSuggestions(specs: CustomFieldSpec[]): string[] {
  const out = new Set<string>()
  ;(specs || []).forEach((spec) => {
    const rootName = String(spec.name || '').trim()
    if (!rootName) return
    out.add(rootName)
    if (spec.mode !== 'json') {
      inferProfilePathSuggestionsFromExpression(spec.expression).forEach((pathName) => out.add(pathName))
      return
    }
    const keyPaths = extractJsonTemplateKeyPaths(spec.jsonTemplate)
    keyPaths.forEach((path) => {
      const normalized = String(path || '').trim()
      if (!normalized) return
      out.add(normalized)
      out.add(`${rootName}.${normalized}`)
    })
    try {
      const parsed = parseJsonTemplateLikeValue(spec.jsonTemplate)
      collectProfilePathSuggestionsFromJsonValue(parsed, out, rootName)
    } catch {
      // Keep best-effort key suggestions even while the JSON template is being edited.
    }
  })
  return uniqueFieldNames(Array.from(out))
}

function buildCustomOutputFieldPaths(specs: CustomFieldSpec[]): string[] {
  const out = new Set<string>()
  ;(specs || []).forEach((spec) => {
    const rootName = String(spec.name || '').trim()
    if (!rootName) return
    out.add(rootName)
    if (spec.mode !== 'json') return
    const keyPaths = extractJsonTemplateKeyPaths(spec.jsonTemplate)
    keyPaths.forEach((path) => {
      const normalized = String(path || '').trim()
      if (!normalized) return
      out.add(`${rootName}.${normalized}`)
    })
  })
  return uniqueFieldNames(Array.from(out))
}

const INTERNAL_FIELD_ROOT_PREFIXES = ['_lmdb_', '__lmdb_', '_profile_', '_detected_', '_preview_']
const INTERNAL_FIELD_ROOT_EXACT = new Set([
  '_lmdb_entity_meta',
  '_lmdb_profile_source',
  '_lmdb_value_kind',
  '__lmdb_preview_row_id',
  '__lmdb_preview_row_index',
  '_profile_changed_fields',
  '_row_count',
  'lmdb_key',
  'lmdb_entity_key',
])
const LMDB_GLOBAL_ALL_COLUMNS = '__ALL__'
const LMDB_EMPTY_FILTER_TOKEN = '__LMDB_EMPTY__'

function isInternalSystemField(fieldName: string): boolean {
  const text = String(fieldName || '').trim()
  if (!text) return false
  const rootMatch = text.match(/^[^.[\]]+/)
  const root = String(rootMatch?.[0] || text).trim()
  if (!root) return false
  if (INTERNAL_FIELD_ROOT_EXACT.has(root)) return true
  const segments = text.split(/[.[\]]+/).map((part) => part.trim()).filter(Boolean)
  if (segments.includes('_fns_v2')) return true
  return INTERNAL_FIELD_ROOT_PREFIXES.some((prefix) => root.startsWith(prefix))
}

function filterUserFacingFieldNames(values: string[]): string[] {
  return uniqueFieldNames(values).filter((name) => !isInternalSystemField(name))
}

function parseFieldList(value: unknown): string[] {
  if (Array.isArray(value)) {
    return uniqueFieldNames(value.map((v) => String(v)))
  }
  if (typeof value === 'string') {
    return uniqueFieldNames(value.split(/[,\n]/).map((p) => p.trim()))
  }
  return []
}

function parseStringList(value: unknown): string[] {
  if (Array.isArray(value)) {
    const out: string[] = []
    const seen = new Set<string>()
    value.forEach((item) => {
      const text = String(item || '').trim()
      if (!text || seen.has(text)) return
      seen.add(text)
      out.push(text)
    })
    return out
  }
  if (typeof value === 'string') {
    const out: string[] = []
    const seen = new Set<string>()
    value.split(/[,\n]/).forEach((item) => {
      const text = String(item || '').trim()
      if (!text || seen.has(text)) return
      seen.add(text)
      out.push(text)
    })
    return out
  }
  return []
}

function gatewayNumber(value: unknown, fallback = 0): number {
  const n = Number(value)
  return Number.isFinite(n) ? n : fallback
}

function gatewayPercent(value: unknown): number {
  return Math.max(0, Math.min(100, gatewayNumber(value, 0)))
}

function gatewayTimestampText(value: unknown): string {
  const raw = String(value || '').trim()
  if (!raw) return ''
  const date = new Date(raw)
  if (Number.isNaN(date.getTime())) return raw
  return date.toLocaleString()
}

function gatewayProtocolColor(protocol: unknown): string {
  const text = String(protocol || '').trim().toLowerCase()
  if (text === 'graphql') return '#a855f7'
  if (text === 'soap') return '#f59e0b'
  if (text === 'tcp') return '#06b6d4'
  if (text === 'websocket') return '#ec4899'
  return '#6366f1'
}

function gatewayRouteDraftFromRegisteredRoute(route: Record<string, unknown>): GatewayStudioDraft {
  const requestMapping = route.request_mapping && typeof route.request_mapping === 'object' && !Array.isArray(route.request_mapping)
    ? route.request_mapping as Record<string, unknown>
    : {}
  const responseMapping = route.response_mapping && typeof route.response_mapping === 'object' && !Array.isArray(route.response_mapping)
    ? route.response_mapping as Record<string, unknown>
    : {}
  const authConfig = route.auth_config && typeof route.auth_config === 'object' && !Array.isArray(route.auth_config)
    ? route.auth_config as Record<string, unknown>
    : {}
  const rbacConfig = route.rbac_config && typeof route.rbac_config === 'object' && !Array.isArray(route.rbac_config)
    ? route.rbac_config as Record<string, unknown>
    : {}
  const rateLimitConfig = route.rate_limit_config && typeof route.rate_limit_config === 'object' && !Array.isArray(route.rate_limit_config)
    ? route.rate_limit_config as Record<string, unknown>
    : {}
  return createGatewayStudioDraft({
    route_id: route.id,
    gateway_name: route.name,
    enabled: route.enabled,
    protocol: route.protocol,
    api_version: route.version,
    route_method: route.method,
    route_path: route.path,
    source_node_id: route.source_node_id,
    trigger_node_ids: requestMapping.trigger_node_ids || requestMapping.execution_node_ids || requestMapping.node_ids,
    source_config: route.source_config,
    request_mapping: requestMapping,
    input_parameters: requestMapping.input_parameters || requestMapping.parameters,
    response_mapping: responseMapping,
    output_fields: responseMapping.output_fields,
    response_limit: responseMapping.limit,
    graphql_field: responseMapping.graphql_field,
    standard_response: route.standard_response,
    auth_type: authConfig.type,
    auth_token: authConfig.token,
    jwt_secret: authConfig.secret,
    jwt_issuer: authConfig.issuer,
    jwt_audience: authConfig.audience,
    rbac_roles: parseStringList(rbacConfig.allowed_roles).join(', '),
    rate_limit_requests: rateLimitConfig.requests,
    rate_limit_window_seconds: rateLimitConfig.window_seconds,
    audit_enabled: route.audit_enabled,
    logging_enabled: route.logging_enabled,
  })
}

function normalizeDataQueryPickerPath(value: unknown): string {
  const text = String(value || '').trim()
  if (!text) return ''
  const match = text.match(/^dqsrc::[^.]+\.(.+)$/)
  if (match && match[1]) {
    return String(match[1]).trim()
  }
  return text
}

function extractDataQuerySourceIdFromFieldRef(value: unknown): string {
  const text = String(value || '').trim()
  if (!text) return ''
  const match = text.match(/^dqsrc::([^.]+)\..+$/)
  return match && match[1] ? String(match[1]).trim() : ''
}

function buildDataQuerySourceFieldRef(sourceId: string, fieldPath: string): string {
  const sid = String(sourceId || '').trim()
  const path = normalizeDataQueryPickerPath(fieldPath)
  if (!sid || !path) return ''
  return `dqsrc::${sid}.${path}`
}

function createMLOpsStage2FieldConfig(seed?: Partial<MLOpsStage2FieldConfig>): MLOpsStage2FieldConfig {
  const normalizePick = <T extends string>(values: unknown, allowed: Set<string>): T[] =>
    uniqueFieldNames(parseStringList(values))
      .map((item) => String(item || '').trim().toLowerCase())
      .filter((item) => allowed.has(item)) as T[]

  const cleaningAllowed = new Set(MLOPS_STAGE2_CLEANING_OPTIONS.map((item) => item.value))
  const missingAllowed = new Set(MLOPS_STAGE2_MISSING_OPTIONS.map((item) => item.value))
  const encodingAllowed = new Set(MLOPS_STAGE2_ENCODING_OPTIONS.map((item) => item.value))
  const scalingAllowed = new Set(MLOPS_STAGE2_SCALING_OPTIONS.map((item) => item.value))
  const normalizeNumericMap = (value: unknown): Record<string, number> => {
    if (!value || typeof value !== 'object' || Array.isArray(value)) return {}
    const out: Record<string, number> = {}
    Object.entries(value as Record<string, unknown>).forEach(([key, raw]) => {
      const cleanKey = String(key || '').trim()
      if (!cleanKey) return
      const num = Number(raw)
      if (Number.isFinite(num)) out[cleanKey] = num
    })
    return out
  }
  const smoothing = Number(seed?.target_encoding_smoothing ?? 10)
  return {
    field_path: String(seed?.field_path || '').trim(),
    enabled: Boolean(seed?.enabled),
    cleaning: normalizePick<MLOpsStage2CleaningOperation>(seed?.cleaning || [], cleaningAllowed),
    missing_values: normalizePick<MLOpsStage2MissingOperation>(seed?.missing_values || [], missingAllowed),
    encoding: normalizePick<MLOpsStage2EncodingOperation>(seed?.encoding || [], encodingAllowed),
    scaling: normalizePick<MLOpsStage2ScalingOperation>(seed?.scaling || [], scalingAllowed),
    ordinal_mapping: normalizeNumericMap(seed?.ordinal_mapping),
    binary_mapping: normalizeNumericMap(seed?.binary_mapping),
    target_encoding_smoothing: Number.isFinite(smoothing) ? Math.max(0, Math.min(smoothing, 100000)) : 10,
  }
}

function parseMLOpsStage2FieldConfigs(value: unknown): MLOpsStage2FieldConfig[] {
  let raw = value
  if (typeof raw === 'string' && raw.trim()) {
    try {
      raw = JSON.parse(raw)
    } catch {
      return []
    }
  }
  if (!Array.isArray(raw)) return []
  const out: MLOpsStage2FieldConfig[] = []
  raw.forEach((item) => {
    if (!item || typeof item !== 'object') return
    const rec = item as Record<string, unknown>
    const normalized = createMLOpsStage2FieldConfig({
      field_path: String(rec.field_path || rec.field || rec.path || ''),
      enabled: parseBoolLike(rec.enabled, true),
      cleaning: (rec.cleaning as any) || [],
      missing_values: (rec.missing_values as any) || (rec.missing as any) || [],
      encoding: (rec.encoding as any) || [],
      scaling: (rec.scaling as any) || [],
      ordinal_mapping: (rec.ordinal_mapping as any) || {},
      binary_mapping: (rec.binary_mapping as any) || {},
      target_encoding_smoothing: Number(rec.target_encoding_smoothing ?? 10),
    })
    if (!normalized.field_path) return
    out.push(normalized)
  })
  const byField: Record<string, MLOpsStage2FieldConfig> = {}
  out.forEach((item) => {
    byField[item.field_path] = item
  })
  return Object.values(byField).sort((a, b) => a.field_path.localeCompare(b.field_path))
}

function hasMLOpsStage2FieldOps(config: MLOpsStage2FieldConfig | null | undefined): boolean {
  if (!config) return false
  return (
    config.cleaning.length > 0
    || config.missing_values.length > 0
    || config.encoding.length > 0
    || config.scaling.length > 0
  )
}

function serializeMLOpsStage2FieldConfigMap(
  configByField: Record<string, MLOpsStage2FieldConfig>,
): MLOpsStage2FieldConfig[] {
  const out = Object.values(configByField || {})
    .map((item) => createMLOpsStage2FieldConfig(item))
    .filter((item) => item.field_path)
    .filter((item) => item.enabled || hasMLOpsStage2FieldOps(item))
    .sort((a, b) => a.field_path.localeCompare(b.field_path))
  return out
}

function mlopsStage2ToNumber(value: unknown): number | null {
  if (value == null) return null
  if (typeof value === 'number') return Number.isFinite(value) ? value : null
  if (typeof value === 'boolean') return value ? 1 : 0
  const text = String(value || '').trim()
  if (!text) return null
  const num = Number(text.replace(/,/g, ''))
  return Number.isFinite(num) ? num : null
}

function mlopsStage2IsMissing(value: unknown): boolean {
  if (value == null) return true
  if (typeof value === 'number') return !Number.isFinite(value)
  if (typeof value === 'string') {
    const text = String(value).trim()
    if (!text) return true
    return ['na', 'n/a', 'null', 'none', 'nan', 'undefined', '-'].includes(text.toLowerCase())
  }
  return false
}

function mlopsStage2ToScalar(value: unknown): unknown {
  if (Array.isArray(value)) {
    const first = value.find((item) => !mlopsStage2IsMissing(item))
    return first == null ? null : mlopsStage2ToScalar(first)
  }
  if (value && typeof value === 'object') {
    try {
      return JSON.stringify(value)
    } catch {
      return String(value)
    }
  }
  return value
}

function mlopsStage2Quantile(values: number[], q: number): number {
  if (values.length <= 0) return 0
  if (values.length === 1) return values[0]
  const sorted = [...values].sort((a, b) => a - b)
  const pos = (sorted.length - 1) * Math.min(Math.max(q, 0), 1)
  const lo = Math.floor(pos)
  const hi = Math.ceil(pos)
  if (lo === hi) return sorted[lo]
  const w = pos - lo
  return sorted[lo] * (1 - w) + sorted[hi] * w
}

function createMLOpsStage3TuningParameter(seed?: Partial<MLOpsStage3TuningParameter>): MLOpsStage3TuningParameter {
  return {
    id: String(seed?.id || `tune_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`),
    name: String(seed?.name || '').trim(),
    values: String(seed?.values || '').trim(),
  }
}

function createMLOpsRuleCondition(seed?: Partial<MLOpsRuleCondition>): MLOpsRuleCondition {
  return {
    id: String(seed?.id || `cond_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`),
    field: String(seed?.field || '').trim(),
    operator: String(seed?.operator || 'equals').trim() || 'equals',
    value: String(seed?.value ?? ''),
  }
}

function createMLOpsRuleAction(seed?: Partial<MLOpsRuleAction>): MLOpsRuleAction {
  const mode = String(seed?.mode || 'literal') === 'field' || String(seed?.mode || '') === 'template'
    ? String(seed?.mode) as MLOpsRuleAction['mode']
    : 'literal'
  return {
    id: String(seed?.id || `act_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`),
    field: String(seed?.field || '').trim(),
    mode,
    value: String(seed?.value ?? ''),
  }
}

function createMLOpsRule(seed?: Partial<MLOpsRuleConfig>): MLOpsRuleConfig {
  return {
    id: String(seed?.id || `rule_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`),
    enabled: seed?.enabled !== false,
    join: seed?.join === 'any' ? 'any' : 'all',
    action: seed?.action === 'drop' ? 'drop' : 'apply',
    conditions: Array.isArray(seed?.conditions) && seed.conditions.length > 0
      ? seed.conditions.map((item) => createMLOpsRuleCondition(item))
      : [createMLOpsRuleCondition()],
    actions: Array.isArray(seed?.actions)
      ? seed.actions.map((item) => createMLOpsRuleAction(item))
      : [],
  }
}

function createMLOpsEnsembleModel(seed?: Partial<MLOpsEnsembleModelConfig>, index = 0): MLOpsEnsembleModelConfig {
  const rawTask = String(seed?.task_type || 'classification')
  const task = (['classification', 'regression', 'clustering', 'forecasting', 'anomaly_detection'].includes(rawTask)
    ? rawTask
    : 'classification') as MLOpsEnsembleModelConfig['task_type']
  const id = String(seed?.id || `model_${index + 1}`).trim() || `model_${index + 1}`
  const rawFeatureFields = Array.isArray(seed?.feature_fields) ? seed.feature_fields : []
  const rawInfluenceKeys = Array.isArray(seed?.influence_keys) ? seed.influence_keys : []
  return {
    id,
    enabled: seed?.enabled !== false,
    name: String(seed?.name || `Model ${index + 1}`).trim() || `Model ${index + 1}`,
    task_type: task,
    model: String(seed?.model || MLOPS_STAGE3_MODEL_CATALOG[task]?.[0] || '').trim(),
    feature_fields: uniqueFieldNames(rawFeatureFields.map((item) => String(item || '').trim()).filter(Boolean)),
    target_field: String(seed?.target_field || '').trim(),
    forecast_date_field: String(seed?.forecast_date_field || '').trim(),
    forecast_horizon: Math.max(1, Math.min(Math.trunc(Number(seed?.forecast_horizon || 30)), 3650)),
    forecast_frequency: (String(seed?.forecast_frequency || 'D').toUpperCase() === 'W'
      ? 'W'
      : String(seed?.forecast_frequency || 'D').toUpperCase() === 'M'
        ? 'M'
        : 'D') as MLOpsForecastFrequency,
    forecast_auto_tune_orders: Boolean(seed?.forecast_auto_tune_orders),
    forecast_order_search_max_evals: Math.max(1, Math.min(Math.trunc(Number(seed?.forecast_order_search_max_evals || 16)), 64)),
    prediction_field: String(seed?.prediction_field || `${id}_prediction`).trim() || `${id}_prediction`,
    score_field: String(seed?.score_field || `${id}_prediction_score`).trim(),
    explainability_method: String(seed?.explainability_method || 'off') as MLOpsStage3ExplainabilityMethod,
    influence_field: String(seed?.influence_field || `${id}_top_influencing_features`).trim(),
    influence_limit: Math.max(1, Math.min(Math.trunc(Number(seed?.influence_limit || 5)), 50)),
    influence_keys: rawInfluenceKeys.length > 0
      ? rawInfluenceKeys.map((item) => String(item || '').trim()).filter(Boolean)
      : MLOPS_DEFAULT_INFLUENCE_OUTPUT_KEYS,
    pre_rules: Array.isArray(seed?.pre_rules) ? seed.pre_rules.map((item) => createMLOpsRule(item)) : [],
    post_rules: Array.isArray(seed?.post_rules) ? seed.post_rules.map((item) => createMLOpsRule(item)) : [],
    recommendation: {
      enabled: Boolean(seed?.recommendation?.enabled),
      field: String(seed?.recommendation?.field || 'recommendation').trim() || 'recommendation',
      template: String(seed?.recommendation?.template || ''),
    },
  }
}

function serializeMLOpsRule(rule: MLOpsRuleConfig): Record<string, unknown> {
  return {
    enabled: rule.enabled,
    join: rule.join,
    action: rule.action || 'apply',
    conditions: (rule.conditions || []).map((item) => ({
      field: item.field,
      operator: item.operator,
      value: item.value,
    })).filter((item) => item.field),
    actions: (rule.actions || []).map((item) => ({
      field: item.field,
      mode: item.mode,
      value: item.value,
    })).filter((item) => item.field),
  }
}

function serializeMLOpsEnsembleModels(items: MLOpsEnsembleModelConfig[]): Array<Record<string, unknown>> {
  return (items || []).map((item) => ({
    id: item.id,
    enabled: item.enabled,
    name: item.name,
    task_type: item.task_type,
    model: item.model,
    feature_fields: uniqueFieldNames(item.feature_fields || []),
    target_field: item.target_field || undefined,
    forecast_date_field: item.forecast_date_field || undefined,
    forecast_horizon: item.forecast_horizon,
    forecast_frequency: item.forecast_frequency,
    forecast_auto_tune_orders: item.forecast_auto_tune_orders,
    forecast_order_search_max_evals: item.forecast_order_search_max_evals,
    prediction_field: item.prediction_field,
    score_field: item.score_field,
    explainability_method: item.explainability_method,
    influence_field: item.influence_field,
    influence_limit: item.influence_limit,
    influence_keys: item.influence_keys,
    pre_rules: (item.pre_rules || []).map(serializeMLOpsRule),
    post_rules: (item.post_rules || []).map(serializeMLOpsRule),
    recommendation: item.recommendation,
  }))
}

function formatMLOpsOutcomeMetric(value: unknown): string {
  const n = Number(value)
  if (!Number.isFinite(n)) return value == null ? '-' : String(value)
  if (Math.abs(n) <= 1) return `${(n * 100).toFixed(2)}%`
  return Number.isInteger(n) ? String(n) : n.toFixed(4)
}

function getMLOpsPrimaryOutcomeMetric(summary: Record<string, unknown> | null | undefined, taskType?: string): { label: string; value: string; raw: unknown; source: string } {
  const empty = { label: 'Accuracy', value: '-', raw: null, source: '' }
  if (!summary || typeof summary !== 'object') return empty
  const testMetrics = summary.test_metrics && typeof summary.test_metrics === 'object'
    ? summary.test_metrics as Record<string, unknown>
    : {}
  const trainMetrics = summary.train_metrics && typeof summary.train_metrics === 'object'
    ? summary.train_metrics as Record<string, unknown>
    : {}
  const normalizedTask = String(taskType || summary.task_type || '').toLowerCase()
  const candidates = normalizedTask === 'regression'
    ? ['r2', 'r2_score', 'mae', 'rmse', 'mse']
    : normalizedTask === 'clustering'
      ? ['silhouette_score', 'calinski_harabasz_score', 'davies_bouldin_score']
      : normalizedTask === 'anomaly_detection'
        ? ['accuracy', 'f1', 'f1_score', 'precision', 'recall', 'anomaly_rate']
        : ['accuracy', 'balanced_accuracy', 'f1', 'f1_score', 'precision', 'recall', 'auc', 'roc_auc']
  for (const key of candidates) {
    if (testMetrics[key] != null) {
      return { label: key.replace(/_/g, ' '), value: formatMLOpsOutcomeMetric(testMetrics[key]), raw: testMetrics[key], source: 'test' }
    }
  }
  for (const key of candidates) {
    if (trainMetrics[key] != null) {
      return { label: key.replace(/_/g, ' '), value: formatMLOpsOutcomeMetric(trainMetrics[key]), raw: trainMetrics[key], source: 'train' }
    }
  }
  const firstTest = Object.entries(testMetrics).find(([, value]) => value != null && Number.isFinite(Number(value)))
  if (firstTest) {
    return { label: firstTest[0].replace(/_/g, ' '), value: formatMLOpsOutcomeMetric(firstTest[1]), raw: firstTest[1], source: 'test' }
  }
  return empty
}

function getMLOpsTrainingOutcomeRows(summary: Record<string, unknown> | null | undefined): Array<Record<string, unknown>> {
  if (!summary || typeof summary !== 'object') return []
  const trainMetrics = summary.train_metrics && typeof summary.train_metrics === 'object'
    ? summary.train_metrics as Record<string, unknown>
    : {}
  const testMetrics = summary.test_metrics && typeof summary.test_metrics === 'object'
    ? summary.test_metrics as Record<string, unknown>
    : {}
  const keys = uniqueFieldNames([...Object.keys(trainMetrics), ...Object.keys(testMetrics)])
  return keys.map((key) => ({
    _key: key,
    metric: key.replace(/_/g, ' '),
    train: trainMetrics[key] ?? null,
    test: testMetrics[key] ?? null,
  }))
}

function parseMLOpsStage3TuningParameters(value: unknown): MLOpsStage3TuningParameter[] {
  let raw = value
  if (typeof raw === 'string' && raw.trim()) {
    try {
      raw = JSON.parse(raw)
    } catch {
      return []
    }
  }
  if (!Array.isArray(raw)) return []
  const out: MLOpsStage3TuningParameter[] = []
  const seen = new Set<string>()
  raw.forEach((item) => {
    if (!item || typeof item !== 'object') return
    const normalized = createMLOpsStage3TuningParameter(item as Partial<MLOpsStage3TuningParameter>)
    if (!normalized.id || seen.has(normalized.id)) return
    seen.add(normalized.id)
    out.push(normalized)
  })
  return out
}

function serializeMLOpsStage3TuningParameters(items: MLOpsStage3TuningParameter[]): MLOpsStage3TuningParameter[] {
  const out: MLOpsStage3TuningParameter[] = []
  const seen = new Set<string>()
  ;(items || []).forEach((item) => {
    const normalized = createMLOpsStage3TuningParameter(item)
    if (!normalized.id || seen.has(normalized.id)) return
    seen.add(normalized.id)
    out.push(normalized)
  })
  return out
}

function inferMLOpsStage2FieldKind(values: unknown[]): MLOpsStage2FieldKind {
  const sample = values.filter((value) => !mlopsStage2IsMissing(value)).slice(0, 60)
  if (sample.length <= 0) return 'unknown'
  let numeric = 0
  let dateLike = 0
  let textLike = 0
  let objectLike = 0
  sample.forEach((value) => {
    if (mlopsStage2ToNumber(value) != null) {
      numeric += 1
      return
    }
    if (value && typeof value === 'object') {
      objectLike += 1
      return
    }
    const text = String(value || '').trim()
    if (text) {
      const dateMs = Date.parse(text)
      if (!Number.isNaN(dateMs)) dateLike += 1
      else textLike += 1
    }
  })
  const total = Math.max(sample.length, 1)
  if (numeric / total >= 0.85) return 'numeric'
  if (dateLike / total >= 0.7) return 'datetime'
  if (objectLike > 0) return 'mixed'
  const distinct = new Set(sample.map((item) => String(item || '').trim())).size
  if (textLike > 0 && distinct <= 20) return 'categorical'
  if (textLike > 0) return 'text'
  return 'mixed'
}

function normalizeDataQueryProfilePatchOpKind(value: unknown): DataQueryProfilePatchOpKind {
  const raw = String(value || '').trim().toLowerCase()
  if (raw === 'set_where' || raw === 'unset' || raw === 'inc' || raw === 'append' || raw === 'remove' || raw === 'rename') {
    return raw
  }
  return 'set'
}

function createDataQueryProfilePatchOperation(seed?: Partial<DataQueryProfilePatchOperation>): DataQueryProfilePatchOperation {
  const op = normalizeDataQueryProfilePatchOpKind(seed?.op)
  const valueMode: DataQueryProfilePatchValueMode = String(seed?.valueMode || '').trim().toLowerCase() === 'fixed' ? 'fixed' : 'row'
  const mergeMode: 'merge' | 'replace' = String(seed?.mergeMode || '').trim().toLowerCase() === 'replace' ? 'replace' : 'merge'
  return {
    id: String(seed?.id || `patch_op_${Date.now()}_${Math.floor(Math.random() * 100000)}`),
    op,
    targetPath: String(seed?.targetPath || '').trim(),
    sourcePath: String(seed?.sourcePath || '').trim(),
    valueMode,
    value: String(seed?.value ?? ''),
    whereField: String((seed as any)?.whereField || '').trim(),
    whereValueMode: String((seed as any)?.whereValueMode || '').trim().toLowerCase() === 'fixed' ? 'fixed' : 'row',
    whereSourcePath: String((seed as any)?.whereSourcePath || '').trim(),
    whereValue: String((seed as any)?.whereValue ?? ''),
    renameTo: String(seed?.renameTo || '').trim(),
    mergeMode,
  }
}

function parseDataQueryProfilePatchOperations(value: unknown): DataQueryProfilePatchOperation[] {
  let raw = value
  if (typeof raw === 'string') {
    const text = raw.trim()
    if (!text) return []
    try {
      raw = JSON.parse(text)
    } catch {
      return []
    }
  }
  if (!Array.isArray(raw)) return []
  const out = raw
    .map((item) => {
      if (!item || typeof item !== 'object') return null
      const rec = item as Record<string, unknown>
      return createDataQueryProfilePatchOperation({
        id: String(rec.id || ''),
        op: normalizeDataQueryProfilePatchOpKind(rec.op ?? rec.operation ?? rec.type),
        targetPath: String(rec.target_path ?? rec.path ?? rec.target ?? ''),
        sourcePath: String(rec.source_path ?? rec.document_path ?? ''),
        valueMode: String(rec.value_mode ?? 'row') as DataQueryProfilePatchValueMode,
        value: String(rec.value ?? ''),
        whereField: String(rec.where_field ?? rec.match_field ?? ''),
        whereValueMode: String(rec.where_value_mode ?? rec.match_value_mode ?? 'row') as DataQueryProfilePatchValueMode,
        whereSourcePath: String(rec.where_source_path ?? rec.match_source_path ?? ''),
        whereValue: String(rec.where_value ?? rec.match_value ?? ''),
        renameTo: String(rec.rename_to ?? rec.new_name ?? rec.new_key ?? ''),
        mergeMode: String(rec.merge_mode ?? 'merge') === 'replace' ? 'replace' : 'merge',
      })
    })
    .filter((item): item is DataQueryProfilePatchOperation => !!item)
  return out
}

function serializeDataQueryProfilePatchOperations(items: DataQueryProfilePatchOperation[]): Array<Record<string, unknown>> {
  return (items || [])
    .map((item) => ({
      id: String(item.id || '').trim(),
      op: normalizeDataQueryProfilePatchOpKind(item.op),
      target_path: String(item.targetPath || '').trim(),
      source_path: String(item.sourcePath || '').trim(),
      value_mode: String(item.valueMode || '').trim().toLowerCase() === 'fixed' ? 'fixed' : 'row',
      value: String(item.value ?? ''),
      where_field: String(item.whereField || '').trim(),
      where_value_mode: String(item.whereValueMode || '').trim().toLowerCase() === 'fixed' ? 'fixed' : 'row',
      where_source_path: String(item.whereSourcePath || '').trim(),
      where_value: String(item.whereValue ?? ''),
      rename_to: String(item.renameTo || '').trim(),
      merge_mode: String(item.mergeMode || '').trim().toLowerCase() === 'replace' ? 'replace' : 'merge',
    }))
    .filter((item) => {
      const op = normalizeDataQueryProfilePatchOpKind(item.op)
      const targetPath = String(item.target_path || '').trim()
      if (op === 'rename') return Boolean(targetPath && String(item.rename_to || '').trim())
      if (op === 'set_where') return Boolean(targetPath)
      if (op === 'set' || op === 'inc' || op === 'append' || op === 'remove' || op === 'unset') return Boolean(targetPath)
      return Boolean(targetPath)
    })
}

function parseJsonArraySafe(value: unknown): unknown[] {
  if (Array.isArray(value)) return value
  if (typeof value === 'string') {
    const text = value.trim()
    if (!text) return []
    try {
      const parsed = JSON.parse(text)
      return Array.isArray(parsed) ? parsed : []
    } catch {
      return []
    }
  }
  return []
}

function normalizeConditionCaseHandleId(rawRouteId: unknown): string {
  const raw = String(rawRouteId || '').trim().toLowerCase()
  const safe = raw.replace(/[^a-z0-9_]+/g, '_').replace(/^_+|_+$/g, '') || `route_${Date.now()}`
  return `case_${safe}`
}

function resolveConditionTargetIdsForNodes(
  nodes: ETLNode[],
  rawTargets: unknown,
  sourceNodeId?: string,
): string[] {
  const sourceId = String(sourceNodeId || '').trim()
  const idSet = new Set<string>()
  const labelExact = new Map<string, string>()
  const labelLower = new Map<string, string>()
  nodes.forEach((item) => {
    const idText = String(item.id || '').trim()
    if (!idText) return
    idSet.add(idText)
    const label = String(item.data?.label || item.data?.nodeType || item.id || '').trim()
    if (!label) return
    if (!labelExact.has(label)) labelExact.set(label, idText)
    const lowerKey = label.toLowerCase()
    if (!labelLower.has(lowerKey)) labelLower.set(lowerKey, idText)
  })

  const out: string[] = []
  const seen = new Set<string>()
  parseStringList(rawTargets).forEach((tokenRaw) => {
    const token = String(tokenRaw || '').trim()
    if (!token) return
    let resolved = ''
    if (idSet.has(token)) {
      resolved = token
    } else if (labelExact.has(token)) {
      resolved = String(labelExact.get(token) || '').trim()
    } else if (labelLower.has(token.toLowerCase())) {
      resolved = String(labelLower.get(token.toLowerCase()) || '').trim()
    } else {
      const uuidHit = token.match(/[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}/i)
      const guessed = String(uuidHit?.[0] || '').trim()
      if (guessed && idSet.has(guessed)) resolved = guessed
    }
    if (!resolved) return
    if (sourceId && resolved === sourceId) return
    if (seen.has(resolved)) return
    seen.add(resolved)
    out.push(resolved)
  })
  return out
}

function createConditionCaseCondition(seed?: Partial<ConditionCaseCondition>): ConditionCaseCondition {
  const conditionId = String(seed?.id || `cond_${Date.now()}`).trim()
  const rawMode = String((seed as any)?.mode || (seed as any)?.matchMode || (seed as any)?.match_mode || '').trim().toLowerCase()
  const mode: ConditionCaseRouteMode = rawMode === 'condition' ? 'condition' : 'range'
  const rawRightMode = String((seed as any)?.rightMode || (seed as any)?.right_mode || '').trim().toLowerCase()
  const rightMode: ConditionCaseRouteRightMode = rawRightMode === 'field' ? 'field' : 'literal'
  return {
    id: conditionId,
    field: String(seed?.field || '').trim(),
    mode,
    operator: String((seed as any)?.operator || 'equals').trim() || 'equals',
    rightMode,
    rightValue: (seed as any)?.rightValue == null
      ? ((seed as any)?.right_value == null ? '' : String((seed as any).right_value))
      : String((seed as any).rightValue),
    minValue: seed?.minValue == null ? '' : String(seed.minValue),
    maxValue: seed?.maxValue == null ? '' : String(seed.maxValue),
    includeMin: seed?.includeMin !== false,
    includeMax: seed?.includeMax !== false,
  }
}

function createConditionCaseRoute(seed?: Partial<ConditionCaseRoute>): ConditionCaseRoute {
  const routeId = String(seed?.id || `route_${Date.now()}`).trim()
  const routeHandleId = String((seed as any)?.handleId || (seed as any)?.handle_id || normalizeConditionCaseHandleId(routeId)).trim()
  const rawMatchMode = String((seed as any)?.matchMode || (seed as any)?.match_mode || '').trim().toLowerCase()
  const matchMode: ConditionCaseRouteMatchMode = rawMatchMode === 'any' ? 'any' : 'all'
  let conditions: ConditionCaseCondition[] = []
  if (Array.isArray((seed as any)?.conditions)) {
    conditions = ((seed as any).conditions as Array<Partial<ConditionCaseCondition>>)
      .map((item) => createConditionCaseCondition(item))
      .filter((item) => Boolean(String(item.id || '').trim()))
  }
  if (conditions.length === 0) {
    conditions = [createConditionCaseCondition({
      id: `cond_${Date.now()}`,
      field: String(seed?.field || '').trim(),
      mode: String((seed as any)?.mode || (seed as any)?.matchMode || (seed as any)?.match_mode || '').trim().toLowerCase() === 'condition'
        ? 'condition'
        : 'range',
      operator: String((seed as any)?.operator || 'equals').trim() || 'equals',
      rightMode: String((seed as any)?.rightMode || (seed as any)?.right_mode || '').trim().toLowerCase() === 'field' ? 'field' : 'literal',
      rightValue: (seed as any)?.rightValue == null
        ? ((seed as any)?.right_value == null ? '' : String((seed as any).right_value))
        : String((seed as any).rightValue),
      minValue: seed?.minValue == null ? '' : String(seed.minValue),
      maxValue: seed?.maxValue == null ? '' : String(seed.maxValue),
      includeMin: seed?.includeMin !== false,
      includeMax: seed?.includeMax !== false,
    })]
  }
  const first = conditions[0] || createConditionCaseCondition()
  return {
    id: routeId,
    label: String(seed?.label || routeId || 'CASE').trim() || 'CASE',
    handleId: routeHandleId || normalizeConditionCaseHandleId(routeId),
    matchMode,
    conditions,
    field: String(first.field || '').trim(),
    mode: first.mode,
    operator: String(first.operator || 'equals').trim() || 'equals',
    rightMode: first.rightMode,
    rightValue: String(first.rightValue ?? ''),
    minValue: String(first.minValue ?? ''),
    maxValue: String(first.maxValue ?? ''),
    includeMin: first.includeMin !== false,
    includeMax: first.includeMax !== false,
    targetNodeIds: parseStringList(seed?.targetNodeIds || []),
  }
}

function parseConditionCaseRoutes(value: unknown): ConditionCaseRoute[] {
  let raw: unknown = value
  if (typeof raw === 'string') {
    try {
      raw = JSON.parse(raw)
    } catch {
      raw = []
    }
  }
  if (!Array.isArray(raw)) return []
  const routes: ConditionCaseRoute[] = []
  raw.forEach((item, index) => {
    if (!item || typeof item !== 'object') return
    const src = item as Record<string, unknown>
    const id = String(src.id || `route_${index + 1}`).trim() || `route_${index + 1}`
    const parsedConditions = Array.isArray(src.conditions)
      ? (src.conditions as Array<Record<string, unknown>>).map((cond, condIdx) => createConditionCaseCondition({
        id: String(cond?.id || `cond_${id}_${condIdx + 1}`),
        field: String(cond?.field || cond?.leftField || '').trim(),
        mode: String(cond?.mode || cond?.matchMode || cond?.match_mode || '').trim().toLowerCase() === 'condition' ? 'condition' : 'range',
        operator: String(cond?.operator || 'equals').trim(),
        rightMode: String(cond?.rightMode || cond?.right_mode || '').trim().toLowerCase() === 'field' ? 'field' : 'literal',
        rightValue: cond?.rightValue == null ? (cond?.right_value == null ? '' : String(cond?.right_value)) : String(cond?.rightValue),
        minValue: cond?.minValue == null ? (cond?.min_value == null ? '' : String(cond?.min_value)) : String(cond?.minValue),
        maxValue: cond?.maxValue == null ? (cond?.max_value == null ? '' : String(cond?.max_value)) : String(cond?.maxValue),
        includeMin: cond?.includeMin == null ? (cond?.include_min == null ? true : Boolean(cond?.include_min)) : Boolean(cond?.includeMin),
        includeMax: cond?.includeMax == null ? (cond?.include_max == null ? true : Boolean(cond?.include_max)) : Boolean(cond?.includeMax),
      }))
      : []
    routes.push(createConditionCaseRoute({
      id,
      label: String(src.label || src.name || id).trim(),
      handleId: String(src.handle_id || src.handleId || '').trim() || normalizeConditionCaseHandleId(id),
      matchMode: String(src.matchMode || src.route_match_mode || src.match_mode || '').trim().toLowerCase() === 'any' ? 'any' : 'all',
      conditions: parsedConditions,
      field: String(src.field || src.leftField || '').trim(),
      mode: String(src.mode || src.matchMode || src.match_mode || '').trim().toLowerCase() === 'condition' ? 'condition' : 'range',
      operator: String(src.operator || 'equals').trim(),
      rightMode: String(src.rightMode || src.right_mode || '').trim().toLowerCase() === 'field' ? 'field' : 'literal',
      rightValue: src.rightValue == null ? (src.right_value == null ? '' : String(src.right_value)) : String(src.rightValue),
      minValue: src.minValue == null ? (src.min_value == null ? '' : String(src.min_value)) : String(src.minValue),
      maxValue: src.maxValue == null ? (src.max_value == null ? '' : String(src.max_value)) : String(src.maxValue),
      includeMin: src.includeMin == null ? (src.include_min == null ? true : Boolean(src.include_min)) : Boolean(src.includeMin),
      includeMax: src.includeMax == null ? (src.include_max == null ? true : Boolean(src.include_max)) : Boolean(src.includeMax),
      targetNodeIds: parseStringList(src.targetNodeIds || src.target_node_ids || []),
    }))
  })
  return routes
}

function parseDetectedJsonPaths(value: unknown): string[] {
  if (!Array.isArray(value)) return []
  const out: string[] = []
  value.forEach((item) => {
    if (typeof item === 'string') out.push(item)
    else if (item && typeof item === 'object') {
      const src = item as any
      const candidates = [
        src.value,
        src.path,
        src.json_path,
        src.field,
        src.name,
      ]
      candidates.forEach((candidate) => {
        const v = String(candidate || '').trim()
        if (v) out.push(v)
      })
    }
  })
  return uniqueFieldNames(out.filter((p) => p && p !== '$'))
}

function extractEmbeddedJsonCandidates(text: string): string[] {
  const src = String(text || '').trim()
  if (!src) return []
  const out = new Set<string>()
  const pushSlice = (openCh: '{' | '[', closeCh: '}' | ']') => {
    const start = src.indexOf(openCh)
    const end = src.lastIndexOf(closeCh)
    if (start === -1 || end === -1 || end <= start) return
    const slice = src.slice(start, end + 1).trim()
    if (slice.length >= 2) out.add(slice)
  }
  pushSlice('{', '}')
  pushSlice('[', ']')
  return Array.from(out)
}

function parseObjectLikeJsonString(value: unknown): unknown {
  if (typeof value !== 'string') return null
  if (value.length > MAX_PARSEABLE_OBJECTLIKE_TEXT_CHARS) return null
  const base = value.trim()
  if (!base) return null
  const queue: string[] = [base, ...extractEmbeddedJsonCandidates(base)]
  const seen = new Set<string>()
  while (queue.length > 0) {
    const text = String(queue.shift() || '').trim()
    if (!text || seen.has(text)) continue
    seen.add(text)
    const startsJson = (text.startsWith('{') && text.endsWith('}')) || (text.startsWith('[') && text.endsWith(']'))
    const wrapped = (
      (text.startsWith('"') && text.endsWith('"'))
      || (text.startsWith("'") && text.endsWith("'"))
    )
    if (wrapped) {
      const inner = text.slice(1, -1).trim()
      if (inner && !seen.has(inner)) queue.push(inner)
      const decodedInner = decodeJsonStringContent(inner).trim()
      if (decodedInner && !seen.has(decodedInner)) queue.push(decodedInner)
    }
    if (!startsJson && !wrapped) continue
    try {
      const parsed = JSON.parse(text)
      if (parsed && (Array.isArray(parsed) || typeof parsed === 'object')) return parsed
      if (typeof parsed === 'string' && parsed.trim() && !seen.has(parsed.trim())) {
        queue.push(parsed.trim())
      }
      continue
    } catch {
      const normalized = text
        .replace(/\bNone\b/g, 'null')
        .replace(/\bTrue\b/g, 'true')
        .replace(/\bFalse\b/g, 'false')
        .replace(/([{,]\s*)'([^'\\]+?)'\s*:/g, '$1"$2":')
        .replace(/([{,]\s*)([A-Za-z_][A-Za-z0-9_.\- ]*)\s*:/g, '$1"$2":')
        .replace(/:\s*'([^'\\]*?)'(\s*[,}\]])/g, ': "$1"$2')
        .replace(/,\s*'([^'\\]*?)'(?=\s*[,}\]])/g, ', "$1"')
      try {
        const parsedFallback = JSON.parse(normalized)
        if (parsedFallback && (Array.isArray(parsedFallback) || typeof parsedFallback === 'object')) return parsedFallback
        if (typeof parsedFallback === 'string') {
          const parsedFallbackString = String(parsedFallback || '').trim()
          if (parsedFallbackString && !seen.has(parsedFallbackString)) queue.push(parsedFallbackString)
        }
      } catch {
        // Handle double-encoded JSON-like strings that may contain escaped braces/quotes.
        const decodedNormalized = decodeJsonStringContent(normalized).trim()
        if (decodedNormalized && !seen.has(decodedNormalized)) queue.push(decodedNormalized)
      }
      if (text.includes('\\')) {
        const decodedText = decodeJsonStringContent(text).trim()
        if (decodedText && !seen.has(decodedText)) queue.push(decodedText)
      }
    }
  }
  return null
}

function extractObjectLikeKeyCandidates(value: unknown, limit = MAX_OBJECT_KEYS_PER_LEVEL): string[] {
  if (typeof value !== 'string') return []
  const text = String(value || '').trim()
  if (!text) return []
  const firstBrace = text.indexOf('{')
  const firstBracket = text.indexOf('[')
  const firstContainerIdx = [firstBrace, firstBracket]
    .filter((idx) => idx >= 0)
    .sort((a, b) => a - b)[0]
  const containerText = (
    (text.startsWith('{') && text.endsWith('}'))
    || (text.startsWith('[') && text.endsWith(']'))
    || ((text.startsWith('"') || text.startsWith("'")) && (text.endsWith('"') || text.endsWith("'")))
  )
    ? text
    : (firstContainerIdx !== undefined ? text.slice(firstContainerIdx) : text)
  if (!containerText) return []
  const out: string[] = []
  const seen = new Set<string>()
  const pattern = /["']([^"']{1,160})["']\s*:/g
  let match: RegExpExecArray | null = null
  while ((match = pattern.exec(containerText)) !== null) {
    const key = String(match[1] || '').trim()
    if (!key || seen.has(key)) continue
    seen.add(key)
    out.push(key)
    if (out.length >= Math.max(1, limit)) break
  }
  if (out.length < Math.max(1, limit)) {
    const barePattern = /(?:^|[{,]\s*)([A-Za-z_][A-Za-z0-9_.\- ]{0,120})\s*:/g
    let bareMatch: RegExpExecArray | null = null
    while ((bareMatch = barePattern.exec(containerText)) !== null) {
      const key = String(bareMatch[1] || '').trim()
      if (!key || seen.has(key)) continue
      seen.add(key)
      out.push(key)
      if (out.length >= Math.max(1, limit)) break
    }
  }
  return out
}

function collectFieldPathsFromValue(value: unknown, basePath: string, out: Set<string>, depth: number): void {
  if (depth > MAX_PATH_DEPTH || out.size >= MAX_PATH_OPTIONS) return

  const parsedJson = parseObjectLikeJsonString(value)
  if (parsedJson && (Array.isArray(parsedJson) || typeof parsedJson === 'object')) {
    collectFieldPathsFromValue(parsedJson, basePath, out, depth + 1)
    return
  }
  if (typeof value === 'string') {
    const looseKeys = extractObjectLikeKeyCandidates(value, MAX_OBJECT_KEYS_PER_LEVEL)
    looseKeys.forEach((key) => {
      const nextPath = appendPathSegment(basePath, key)
      if (out.size < MAX_PATH_OPTIONS) out.add(nextPath)
    })
  }

  if (Array.isArray(value)) {
    if (basePath) out.add(basePath)
    const wildcardPath = basePath ? `${basePath}[]` : ''
    if (wildcardPath) out.add(wildcardPath)

    const sampleItems = value.slice(0, MAX_ARRAY_INDEX_OPTIONS)
    sampleItems.forEach((item, idx) => {
      const idxPath = basePath ? `${basePath}[${idx}]` : `[${idx}]`
      if (out.size < MAX_PATH_OPTIONS) out.add(idxPath)
      collectFieldPathsFromValue(item, idxPath, out, depth + 1)
    })

    if (wildcardPath) {
      const exemplar = value.find((item) => item !== null && item !== undefined)
      if (exemplar !== undefined) {
        collectFieldPathsFromValue(exemplar, wildcardPath, out, depth + 1)
      }
    }
    return
  }

  if (value && typeof value === 'object') {
    const entries = Object.entries(value as Record<string, unknown>).slice(0, MAX_OBJECT_KEYS_PER_LEVEL)
    entries.forEach(([key, child]) => {
      const nextPath = appendPathSegment(basePath, key)
      if (out.size < MAX_PATH_OPTIONS) out.add(nextPath)
      collectFieldPathsFromValue(child, nextPath, out, depth + 1)
    })
  }
}

function extractSampleFieldPaths(rows: unknown): string[] {
  if (!Array.isArray(rows) || rows.length === 0) return []
  const out = new Set<string>()
  rows.slice(0, MAX_SAMPLE_ROWS_FOR_PATH_DISCOVERY).forEach((row) => {
    collectFieldPathsFromValue(row, '', out, 0)
  })
  return uniqueFieldNames(Array.from(out))
}

function extractPriorityJsonFieldPaths(rows: unknown): string[] {
  if (!Array.isArray(rows) || rows.length === 0) return []
  const out = new Set<string>()
  const matchPriorityField = (obj: Record<string, unknown>, wanted: string): string | null => {
    const target = wanted.toLowerCase()
    const hit = Object.keys(obj).find((key) => String(key || '').trim().toLowerCase() === target)
    return hit || null
  }
  rows.slice(0, MAX_SAMPLE_ROWS_FOR_PATH_DISCOVERY).forEach((row) => {
    if (!row || typeof row !== 'object' || Array.isArray(row)) return
    const rowObj = row as Record<string, unknown>
    PRIORITY_JSON_FIELD_NAMES.forEach((priorityField) => {
      const actualKey = matchPriorityField(rowObj, priorityField)
      if (!actualKey) return
      const rawValue = rowObj[actualKey]
      if (rawValue && (Array.isArray(rawValue) || typeof rawValue === 'object')) {
        collectFieldPathsFromValue(rawValue, actualKey, out, 0)
        return
      }
      const parsed = parseObjectLikeJsonString(rawValue)
      if (parsed && (Array.isArray(parsed) || typeof parsed === 'object')) {
        collectFieldPathsFromValue(parsed, actualKey, out, 0)
        return
      }
      const looseKeys = extractObjectLikeKeyCandidates(rawValue, MAX_OBJECT_KEYS_PER_LEVEL)
      looseKeys.forEach((key) => {
        const nextPath = appendPathSegment(actualKey, key)
        if (out.size < MAX_PATH_OPTIONS) out.add(nextPath)
      })
    })
  })
  return uniqueFieldNames(Array.from(out))
}

function appendPathSegment(basePath: string, segment: string): string {
  const base = String(basePath || '').trim()
  const token = String(segment || '').trim()
  if (!token) return base
  if (!base) {
    return SIMPLE_PATH_SEGMENT_PATTERN.test(token) ? token : `["${token.replace(/"/g, '\\"')}"]`
  }
  if (SIMPLE_PATH_SEGMENT_PATTERN.test(token)) {
    return `${base}.${token}`
  }
  return `${base}["${token.replace(/"/g, '\\"')}"]`
}

function extractDirectNodeFields(node: ETLNode | undefined): string[] {
  if (!node?.data) return []
  const cfg = (node.data.config && typeof node.data.config === 'object'
    ? node.data.config
    : {}) as Record<string, unknown>

  const fields: string[] = []
  fields.push(...parseFieldList(cfg._detected_columns))
  fields.push(...parseDetectedJsonPaths(cfg._json_paths))
  fields.push(...extractSampleFieldPaths(cfg._preview_rows))
  fields.push(...extractSampleFieldPaths(node.data.executionSampleInput))
  fields.push(...extractSampleFieldPaths(node.data.executionSampleOutput))

  return filterUserFacingFieldNames(fields)
}

function parseRenameMappings(value: unknown): Array<{ from: string; to: string }> {
  if (typeof value !== 'string') return []
  return value
    .split(/\r?\n/)
    .map((line) => line.trim())
    .filter(Boolean)
    .map((line) => {
      const idx = line.indexOf(':')
      if (idx === -1) return null
      const from = line.slice(0, idx).trim()
      const to = line.slice(idx + 1).trim()
      if (!from || !to) return null
      return { from, to }
    })
    .filter((x): x is { from: string; to: string } => !!x)
}

function parseSelectFieldAliases(value: unknown): Record<string, string> {
  const out: Record<string, string> = {}
  const assignFromObject = (obj: Record<string, unknown>) => {
    Object.entries(obj).forEach(([k, v]) => {
      const path = String(k || '').trim()
      const alias = String(v || '').trim()
      if (path && alias) out[path] = alias
    })
  }

  if (value && typeof value === 'object' && !Array.isArray(value)) {
    assignFromObject(value as Record<string, unknown>)
    return out
  }

  if (typeof value === 'string' && value.trim()) {
    try {
      const parsed = JSON.parse(value)
      if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
        assignFromObject(parsed as Record<string, unknown>)
      }
    } catch {
      return {}
    }
  }
  return out
}

function extractMLOpsOutputFieldsFromConfig(cfg: Record<string, unknown>): string[] {
  const fields: string[] = []
  const add = (value: unknown) => {
    const field = String(value || '').trim()
    if (field) fields.push(field)
  }
  add(cfg.mlops_prediction_field)
  add(cfg.mlops_prediction_score_field)
  const ensembleRaw = cfg.mlops_stage3_ensemble_models
  let ensembleModels: unknown[] = []
  if (Array.isArray(ensembleRaw)) {
    ensembleModels = ensembleRaw
  } else if (typeof ensembleRaw === 'string' && ensembleRaw.trim()) {
    try {
      const parsed = JSON.parse(ensembleRaw)
      if (Array.isArray(parsed)) ensembleModels = parsed
    } catch {
      ensembleModels = []
    }
  }
  ensembleModels.forEach((item, index) => {
    if (!item || typeof item !== 'object' || Array.isArray(item)) return
    const model = item as Record<string, unknown>
    const modelId = String(model.id || `model_${index + 1}`).trim()
    add(model.prediction_field)
    add(model.score_field)
    if (modelId) {
      fields.push(`${modelId}_prediction`)
      fields.push(`${modelId}_prediction_score`)
    }
  })
  return uniqueFieldNames(fields)
}

function normalizeCronExpr(value: unknown): string {
  return String(value || '').trim().split(/\s+/).join(' ')
}

function detectSchedulePresetFromCron(value: unknown): string {
  const normalized = normalizeCronExpr(value)
  if (!normalized) return DEFAULT_SCHEDULE_PRESET
  const hit = Object.entries(SCHEDULE_PRESET_TO_CRON).find(([, cron]) => cron === normalized)
  return hit ? hit[0] : CUSTOM_SCHEDULE_PRESET
}

function inferNodeOutputFields(
  nodeId: string,
  nodesById: Map<string, ETLNode>,
  incomingByTarget: Map<string, string[]>,
  memo: Map<string, string[]>,
  stack: Set<string>
): string[] {
  if (memo.has(nodeId)) return memo.get(nodeId) || []
  if (stack.has(nodeId)) return []
  stack.add(nodeId)

  const node = nodesById.get(nodeId)
  const nodeType = String(node?.data?.nodeType || '')
  const cfg = (node?.data?.config && typeof node?.data?.config === 'object'
    ? node.data.config
    : {}) as Record<string, unknown>
  const directFields = extractDirectNodeFields(node)
  const upstreamIds = incomingByTarget.get(nodeId) || []
  const upstreamFields = uniqueFieldNames(
    upstreamIds.flatMap((srcId) => inferNodeOutputFields(srcId, nodesById, incomingByTarget, memo, stack))
  )
  const passthroughFields = upstreamFields.length > 0 ? upstreamFields : directFields

  let result: string[] = passthroughFields
  if (nodeType === 'map_transform') {
    const custom = parseCustomFieldSpecs(cfg.custom_fields)
    const primaryKeyField = String(cfg.custom_primary_key_field || cfg.custom_group_by_field || '').trim()
    if (custom.length > 0) {
      const customNames = uniqueFieldNames([
        ...custom.map((item) => String(item.name || '').trim()).filter(Boolean),
        ...(primaryKeyField ? [primaryKeyField] : []),
      ])
      const customOutputPaths = uniqueFieldNames([
        ...buildCustomOutputFieldPaths(custom),
        ...(primaryKeyField ? [primaryKeyField] : []),
      ])
      const includeSource = Boolean(cfg.custom_include_source_fields ?? true)
      result = includeSource
        ? uniqueFieldNames([...passthroughFields, ...customNames, ...customOutputPaths])
        : uniqueFieldNames([...customNames, ...customOutputPaths])
    } else {
      const selected = parseFieldList(cfg.fields)
      result = selected.length > 0 ? selected : passthroughFields
    }
  } else if (nodeType === 'profile_query_transform') {
    const selected = parseFieldList(cfg.select_fields)
    const selectAliases = parseSelectFieldAliases(cfg.select_field_aliases)
    const aliasNames = uniqueFieldNames(
      selected
        .map((fieldPath) => String(selectAliases[fieldPath] || '').trim())
        .filter(Boolean)
    )
    const selectedWithAliases = uniqueFieldNames([...selected, ...aliasNames])
    const includeOriginal = selectedWithAliases.length > 0
      ? false
      : parseBoolLike(cfg.include_original_row, false)
    if (selectedWithAliases.length > 0) {
      result = includeOriginal
        ? uniqueFieldNames([...passthroughFields, ...selectedWithAliases])
        : selectedWithAliases
    } else {
      result = passthroughFields
    }
  } else if (nodeType === 'rename_transform') {
    const mappings = parseRenameMappings(cfg.mappings)
    if (mappings.length > 0) {
      const mapped = (passthroughFields.length > 0 ? passthroughFields : mappings.map((m) => m.from)).map((f) => {
        const hit = mappings.find((m) => m.from === f)
        return hit ? hit.to : f
      })
      result = uniqueFieldNames([...mapped, ...mappings.map((m) => m.to)])
    }
  } else if (nodeType === 'aggregate_transform') {
    const groupBy = parseFieldList(cfg.group_by)
    const aggField = String(cfg.agg_field || '').trim()
    const out = uniqueFieldNames([...groupBy, ...(aggField ? [aggField] : [])])
    result = out.length > 0 ? out : passthroughFields
  } else if (nodeType === 'mlops_transform') {
    result = uniqueFieldNames([
      ...passthroughFields,
      ...extractMLOpsOutputFieldsFromConfig(cfg),
    ])
  }

  result = filterUserFacingFieldNames(result)
  memo.set(nodeId, result)
  stack.delete(nodeId)
  return result
}

function buildIncomingByTarget(edges: Array<{ source: string; target: string }>): Map<string, string[]> {
  const incomingByTarget = new Map<string, string[]>()
  edges.forEach((edge) => {
    const curr = incomingByTarget.get(edge.target) || []
    curr.push(edge.source)
    incomingByTarget.set(edge.target, curr)
  })
  return incomingByTarget
}

function collectUpstreamNodeIds(
  startNodeId: string,
  incomingByTarget: Map<string, string[]>,
  maxNodes = 1500,
): string[] {
  const start = String(startNodeId || '').trim()
  if (!start) return []
  const out: string[] = []
  const visited = new Set<string>()
  const queue = [start]
  while (queue.length > 0 && out.length < maxNodes) {
    const nodeId = String(queue.shift() || '').trim()
    if (!nodeId || visited.has(nodeId)) continue
    visited.add(nodeId)
    out.push(nodeId)
    const parents = incomingByTarget.get(nodeId) || []
    parents.forEach((pid) => {
      const parentId = String(pid || '').trim()
      if (parentId && !visited.has(parentId)) queue.push(parentId)
    })
  }
  return out
}

function readableNodeTypeLabel(nodeType: unknown): string {
  const text = String(nodeType || 'node').trim()
  if (!text) return 'Node'
  return text
    .split(/[_\s-]+/g)
    .filter(Boolean)
    .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
    .join(' ')
}

function isGatewaySelectableSourceNode(node: ETLNode | undefined, targetNodeId?: string): boolean {
  if (!node) return false
  if (targetNodeId && node.id === targetNodeId) return false
  const data = node.data || {}
  const nodeType = String(data.nodeType || node.type || '').trim().toLowerCase()
  const category = String(data.definition?.category || '').trim().toLowerCase()
  if (!nodeType || nodeType === 'api_gateway') return false
  if (category === 'destination' || category === 'trigger') return false
  if (category === 'source' || category === 'transform') return true
  return nodeType.endsWith('_source') || nodeType.endsWith('_transform')
}

function inferUpstreamInputFields(
  targetNodeId: string,
  nodes: ETLNode[],
  edges: Array<{ source: string; target: string }>,
  preferredSourceNodeIds?: string | string[],
  strictPreferredSource = false,
): string[] {
  const nodesById = new Map(nodes.map((n) => [n.id, n] as const))
  const incomingByTarget = buildIncomingByTarget(edges)

  const allIncomingIds = uniqueFieldNames((incomingByTarget.get(targetNodeId) || []).map((id) => id))
  const preferredIds = uniqueFieldNames(
    parseStringList(preferredSourceNodeIds).filter((id) => nodesById.has(id))
  )
  if (preferredIds.length > 0) {
    const memo = new Map<string, string[]>()
    const fields = uniqueFieldNames(
      preferredIds.flatMap((srcId) =>
        uniqueFieldNames([
          ...inferNodeOutputFields(srcId, nodesById, incomingByTarget, memo, new Set<string>()),
          ...extractDirectNodeFields(nodesById.get(srcId)),
        ])
      )
    )
    return filterUserFacingFieldNames(fields)
  }

  if (strictPreferredSource && parseStringList(preferredSourceNodeIds).length > 0) {
    return []
  }
  const incomingIds = allIncomingIds
  if (incomingIds.length === 0) return []

  const memo = new Map<string, string[]>()
  const fields = uniqueFieldNames(
    incomingIds.flatMap((srcId) =>
      uniqueFieldNames([
        ...inferNodeOutputFields(srcId, nodesById, incomingByTarget, memo, new Set<string>()),
        ...extractDirectNodeFields(nodesById.get(srcId)),
      ])
    )
  )
  return filterUserFacingFieldNames(fields)
}

function inferUpstreamSources(
  targetNodeId: string,
  nodes: ETLNode[],
  edges: Array<{ source: string; target: string }>,
  options?: { includeAllUpstream?: boolean },
): Array<{ id: string; label: string; fields: string[]; nodeType: string; isDirect: boolean; isConnected: boolean; depth: number }> {
  const nodesById = new Map(nodes.map((n) => [n.id, n] as const))
  const incomingByTarget = buildIncomingByTarget(edges)
  const incomingIds = uniqueFieldNames((incomingByTarget.get(targetNodeId) || []).map((id) => id))
  if (incomingIds.length === 0 && !options?.includeAllUpstream) return []

  const memo = new Map<string, string[]>()
  const buildSourceDescriptor = (
    srcId: string,
    labelOverride?: string,
    isDirect = incomingIds.includes(srcId),
    depth = isDirect ? 1 : 2,
    isConnected = true,
  ): { id: string; label: string; fields: string[]; nodeType: string; isDirect: boolean; isConnected: boolean; depth: number } => {
    const srcNode = nodesById.get(srcId)
    const label = String(labelOverride || srcNode?.data?.label || srcNode?.data?.definition?.label || srcId)
    const nodeType = String(srcNode?.data?.nodeType || '').trim().toLowerCase()
    const inferredFields = inferNodeOutputFields(srcId, nodesById, incomingByTarget, memo, new Set<string>())
    const directFields = extractDirectNodeFields(srcNode)
    const fields = uniqueFieldNames([...inferredFields, ...directFields])
    return { id: srcId, label, fields, nodeType, isDirect, isConnected, depth }
  }

  const list: Array<{ id: string; label: string; fields: string[]; nodeType: string; isDirect: boolean; isConnected: boolean; depth: number }> = incomingIds.map((srcId) =>
    buildSourceDescriptor(srcId)
  )
  const seenIds = new Set(list.map((item) => String(item.id || '').trim()).filter(Boolean))
  const incomingSet = new Set(incomingIds)

  if (options?.includeAllUpstream) {
    collectUpstreamNodeIds(targetNodeId, incomingByTarget, 1500).forEach((upId) => {
      const nid = String(upId || '').trim()
      if (!nid || nid === targetNodeId || seenIds.has(nid)) return
      list.push(buildSourceDescriptor(nid, undefined, incomingSet.has(nid), incomingSet.has(nid) ? 1 : 2, true))
      seenIds.add(nid)
    })
    nodes.forEach((node) => {
      const nid = String(node.id || '').trim()
      if (!nid || seenIds.has(nid) || !isGatewaySelectableSourceNode(node, targetNodeId)) return
      list.push(buildSourceDescriptor(nid, undefined, false, 999, false))
      seenIds.add(nid)
    })
    return list.sort((a, b) => {
      if (a.isDirect !== b.isDirect) return a.isDirect ? -1 : 1
      if (a.isConnected !== b.isConnected) return a.isConnected ? -1 : 1
      return a.label.localeCompare(b.label)
    })
  }

  incomingIds.forEach((directId) => {
    const upstreamIds = collectUpstreamNodeIds(directId, incomingByTarget, 1500)
    upstreamIds.forEach((upId) => {
      const nid = String(upId || '').trim()
      if (!nid || seenIds.has(nid) || incomingSet.has(nid)) return
      const upNode = nodesById.get(nid)
      const upType = String(upNode?.data?.nodeType || '').trim().toLowerCase()
      if (upType !== 'profile_query_transform') return
      const baseLabel = String(upNode?.data?.label || upNode?.data?.definition?.label || nid)
      list.push(buildSourceDescriptor(nid, `${baseLabel} (Data Query)`, false, 2, true))
      seenIds.add(nid)
    })
  })

  return list
}

type PreviewExtractOptions = {
  includeConfigPreview?: boolean
  includeExecutionOutput?: boolean
  includeExecutionInput?: boolean
}

function extractPreviewRowsFromNode(
  node: ETLNode | undefined,
  options?: PreviewExtractOptions,
): Array<Record<string, unknown>> {
  if (!node?.data) return []
  const cfg = (node.data.config && typeof node.data.config === 'object'
    ? node.data.config
    : {}) as Record<string, unknown>

  const includeConfigPreview = options?.includeConfigPreview !== false
  const includeExecutionOutput = options?.includeExecutionOutput !== false
  const includeExecutionInput = options?.includeExecutionInput !== false

  const candidateSets = [
    ...(includeConfigPreview ? [cfg._preview_rows] : []),
    ...(includeExecutionOutput ? [node.data.executionSampleOutput] : []),
    ...(includeExecutionInput ? [node.data.executionSampleInput] : []),
  ]

  const out: Array<Record<string, unknown>> = []
  const seen = new Set<string>()
  const buildSignature = (rowObj: Record<string, unknown>): string | null => {
    try {
      const json = JSON.stringify(rowObj)
      if (!json) return null
      if (json.length > MAX_PREVIEW_SIGNATURE_CHARS) return json.slice(0, MAX_PREVIEW_SIGNATURE_CHARS)
      return json
    } catch {
      return null
    }
  }
  const addRow = (rowObj: Record<string, unknown>) => {
    const sig = buildSignature(rowObj)
    if (sig && seen.has(sig)) return
    if (sig) seen.add(sig)
    out.push(rowObj)
  }
  const collectCandidate = (candidate: unknown) => {
    if (candidate == null) return
    if (Array.isArray(candidate)) {
      candidate.forEach((item) => collectCandidate(item))
      return
    }
    if (candidate && typeof candidate === 'object') {
      addRow(candidate as Record<string, unknown>)
      return
    }
    const parsed = parseObjectLikeJsonString(candidate)
    if (parsed == null) return
    collectCandidate(parsed)
  }
  candidateSets.forEach((candidate) => {
    collectCandidate(candidate)
  })
  return out
}

function inferUpstreamPreviewRows(
  targetNodeId: string,
  nodes: ETLNode[],
  edges: Array<{ source: string; target: string }>,
  maxRows = 30,
  preferredSourceNodeIds?: string | string[],
  sourceOutputOnly = false,
  strictPreferredSource = false,
): Array<Record<string, unknown>> {
  const nodesById = new Map(nodes.map((n) => [n.id, n] as const))
  const incomingByTarget = buildIncomingByTarget(edges)
  const allIncomingIds = uniqueFieldNames((incomingByTarget.get(targetNodeId) || []).map((id) => id))
  const outputOnlyOptions: PreviewExtractOptions = {
    includeConfigPreview: false,
    includeExecutionOutput: true,
    includeExecutionInput: false,
  }
  const outputOnlyWithConfigFallbackOptions: PreviewExtractOptions = {
    includeConfigPreview: true,
    includeExecutionOutput: true,
    includeExecutionInput: false,
  }
  const makeRowSignature = (row: Record<string, unknown>): string | null => {
    try {
      const json = JSON.stringify(row)
      if (!json) return null
      if (json.length > MAX_PREVIEW_SIGNATURE_CHARS) return json.slice(0, MAX_PREVIEW_SIGNATURE_CHARS)
      return json
    } catch {
      return null
    }
  }
  const seededRows: Array<Record<string, unknown>> = []
  const seededSeen = new Set<string>()
  const pushSeededRow = (row: Record<string, unknown>) => {
    if (seededRows.length >= maxRows) return
    const sig = makeRowSignature(row)
    if (sig && seededSeen.has(sig)) return
    if (sig) seededSeen.add(sig)
    seededRows.push(row)
  }
  const preferredIdsRaw = parseStringList(preferredSourceNodeIds)
  const preferredIds = uniqueFieldNames(preferredIdsRaw.filter((id) => nodesById.has(id)))
  if (sourceOutputOnly && preferredIds.length === 0 && allIncomingIds.length > 1) {
    // Field discovery mode: when multiple upstream sources are connected and no
    // explicit source is selected, sample from each source first so JSON/doc
    // paths from later sources are not missed.
    const perSourceCap = Math.max(1, Math.floor(maxRows / allIncomingIds.length))
    const merged: Array<Record<string, unknown>> = []
    const seenRows = new Set<string>()
    const pushMerged = (row: Record<string, unknown>) => {
      if (merged.length >= maxRows) return
      const sig = makeRowSignature(row)
      if (sig && seenRows.has(sig)) return
      if (sig) seenRows.add(sig)
      merged.push(row)
    }
    allIncomingIds.forEach((sourceId) => {
      if (merged.length >= maxRows) return
      const sourceNode = nodesById.get(sourceId)
      let sourceRows = extractPreviewRowsFromNode(sourceNode, outputOnlyOptions)
      if (!sourceRows.length) {
        sourceRows = extractPreviewRowsFromNode(sourceNode, outputOnlyWithConfigFallbackOptions)
      }
      if (!sourceRows.length) {
        sourceRows = extractPreviewRowsFromNode(
          sourceNode,
          {
            includeConfigPreview: false,
            includeExecutionOutput: false,
            includeExecutionInput: true,
          },
        )
      }
      sourceRows.slice(0, perSourceCap).forEach(pushMerged)
    })
    if (merged.length > 0) return merged.slice(0, maxRows)
  }
  if (strictPreferredSource && preferredIdsRaw.length > 0 && preferredIds.length === 0) {
    return []
  }
  if (preferredIds.length > 0) {
    // Strict mode for selected source(s): do not mix ancestor nodes outside
    // selected source list; combine selected sources in configured order.
    const directMerged: Array<Record<string, unknown>> = []
    const directSeen = new Set<string>()
    const pushDirectMerged = (row: Record<string, unknown>) => {
      if (directMerged.length >= maxRows) return
      const sig = makeRowSignature(row)
      if (sig && directSeen.has(sig)) return
      if (sig) directSeen.add(sig)
      directMerged.push(row)
    }

    preferredIds.forEach((preferredId) => {
      if (directMerged.length >= maxRows) return
      const preferredNode = nodesById.get(preferredId)
      const rows = extractPreviewRowsFromNode(
        preferredNode,
        sourceOutputOnly
          ? outputOnlyOptions
          : undefined,
      )
      rows.forEach(pushDirectMerged)
    })
    if (directMerged.length > 0) {
      if (!sourceOutputOnly || directMerged.length >= maxRows) {
        return directMerged.slice(0, maxRows)
      }
      // For source-output-only mode, enrich small output samples with config preview
      // rows from the same selected source list (if available), then dedupe.
      preferredIds.forEach((preferredId) => {
        if (directMerged.length >= maxRows) return
        const preferredNode = nodesById.get(preferredId)
        const configRows = extractPreviewRowsFromNode(
          preferredNode,
          {
            includeConfigPreview: true,
            includeExecutionOutput: false,
            includeExecutionInput: false,
          },
        )
        configRows.forEach(pushDirectMerged)
      })
      directMerged.forEach(pushSeededRow)
      if (seededRows.length >= maxRows) return seededRows.slice(0, maxRows)
    }
    if (sourceOutputOnly) {
      const fallbackMerged: Array<Record<string, unknown>> = []
      const fallbackSeen = new Set<string>()
      const pushFallbackMerged = (row: Record<string, unknown>) => {
        if (fallbackMerged.length >= maxRows) return
        const sig = makeRowSignature(row)
        if (sig && fallbackSeen.has(sig)) return
        if (sig) fallbackSeen.add(sig)
        fallbackMerged.push(row)
      }
      preferredIds.forEach((preferredId) => {
        if (fallbackMerged.length >= maxRows) return
        const preferredNode = nodesById.get(preferredId)
        const fallbackRows = extractPreviewRowsFromNode(
          preferredNode,
          outputOnlyWithConfigFallbackOptions,
        )
        fallbackRows.forEach(pushFallbackMerged)
        // Some nodes can have no output sample yet. In that case, include
        // selected-node input sample as fallback.
        if (fallbackMerged.length < maxRows) {
          const inputFallbackRows = extractPreviewRowsFromNode(
            preferredNode,
            {
              includeConfigPreview: false,
              includeExecutionOutput: false,
              includeExecutionInput: true,
            },
          )
          inputFallbackRows.forEach(pushFallbackMerged)
        }
      })
      if (fallbackMerged.length > 0) {
        fallbackMerged.forEach(pushSeededRow)
        if (seededRows.length >= maxRows) return seededRows.slice(0, maxRows)
      }
    }
  }
  const queue = preferredIds.length > 0
    ? [...preferredIds]
    : [...allIncomingIds]
  const visited = new Set<string>()
  const out: Array<Record<string, unknown>> = seededRows.slice(0, maxRows)
  const seen = new Set<string>()
  out.forEach((row) => {
    const sig = makeRowSignature(row)
    if (sig) seen.add(sig)
  })
  const collectRowsForNode = (nodeId: string): Array<Record<string, unknown>> => {
    const node = nodesById.get(nodeId)
    let rows = extractPreviewRowsFromNode(
      node,
      sourceOutputOnly
        ? outputOnlyOptions
        : undefined,
    )
    if (sourceOutputOnly && rows.length === 0) {
      rows = extractPreviewRowsFromNode(node, outputOnlyWithConfigFallbackOptions)
    }
    if (sourceOutputOnly && rows.length === 0) {
      rows = extractPreviewRowsFromNode(
        node,
        {
          includeConfigPreview: false,
          includeExecutionOutput: false,
          includeExecutionInput: true,
        },
      )
    }
    return rows
  }

  if (sourceOutputOnly && out.length < maxRows) {
    // Fair sampling across upstream graph so one node's large sample does not
    // hide sparse JSON/doc fields from deeper/upstream nodes.
    const orderedNodeIds: string[] = []
    const scanQueue = [...queue]
    const scanVisited = new Set<string>()
    while (scanQueue.length > 0 && orderedNodeIds.length < 256) {
      const nodeId = String(scanQueue.shift() || '')
      if (!nodeId || scanVisited.has(nodeId)) continue
      scanVisited.add(nodeId)
      orderedNodeIds.push(nodeId)
      const upstream = incomingByTarget.get(nodeId) || []
      upstream.forEach((srcId) => {
        if (!scanVisited.has(srcId)) scanQueue.push(srcId)
      })
    }

    const buckets = orderedNodeIds.map((nodeId) => ({
      nodeId,
      idx: 0,
      rows: collectRowsForNode(nodeId),
    }))
    let progressed = true
    while (out.length < maxRows && progressed) {
      progressed = false
      for (const bucket of buckets) {
        while (bucket.idx < bucket.rows.length) {
          const row = bucket.rows[bucket.idx]
          bucket.idx += 1
          const sig = makeRowSignature(row)
          if (sig && seen.has(sig)) continue
          if (sig) seen.add(sig)
          out.push(row)
          progressed = true
          break
        }
        if (out.length >= maxRows) break
      }
    }

    if (out.length > 0) {
      return out.slice(0, maxRows)
    }
  }

  while (queue.length > 0 && out.length < maxRows) {
    const nodeId = String(queue.shift() || '')
    if (!nodeId || visited.has(nodeId)) continue
    visited.add(nodeId)

    const rows = collectRowsForNode(nodeId)
    if (rows.length > 0) {
      for (const row of rows) {
        if (out.length >= maxRows) break
        const sig = makeRowSignature(row)
        if (sig && seen.has(sig)) continue
        if (sig) seen.add(sig)
        out.push(row)
      }
      if (out.length >= maxRows) break
    }

    const upstream = incomingByTarget.get(nodeId) || []
    upstream.forEach((srcId) => {
      if (!visited.has(srcId)) queue.push(srcId)
    })
  }

  return out.slice(0, maxRows)
}

function splitPathSegments(path: string): string[] {
  let text = String(path || '').trim()
  if (!text) return []
  if (text === '$') return []
  if (text.startsWith('$.')) text = text.slice(2)
  else if (text.startsWith('$[')) text = text.slice(1)
  if (!text) return []
  const out: string[] = []
  let current = ''
  let bracket = false
  for (let i = 0; i < text.length; i += 1) {
    const ch = text[i]
    if (!bracket && ch === '.') {
      if (current.trim()) out.push(current.trim())
      current = ''
      continue
    }
    if (ch === '[') {
      if (current.trim()) out.push(current.trim())
      current = ''
      bracket = true
      continue
    }
    if (ch === ']') {
      const token = current.trim()
      if (token) {
        const normalized = token.replace(/^['"]|['"]$/g, '').trim()
        out.push(normalized || '*')
      } else {
        out.push('*')
      }
      current = ''
      bracket = false
      continue
    }
    current += ch
  }
  if (current.trim()) out.push(current.trim())
  return out
}

function readPathValues(row: Record<string, unknown>, path: string): unknown[] {
  const rawPath = String(path || '').trim()
  if (!rawPath) return []
  if (Object.prototype.hasOwnProperty.call(row, rawPath)) {
    return [row[rawPath]]
  }
  const normalizedPath = rawPath.startsWith('$.') ? rawPath.slice(2) : (rawPath.startsWith('$[') ? rawPath.slice(1) : rawPath)
  if (normalizedPath && Object.prototype.hasOwnProperty.call(row, normalizedPath)) {
    return [row[normalizedPath]]
  }

  const segments = splitPathSegments(normalizedPath)
  if (segments.length === 0) return []
  const out: unknown[] = []

  if (segments.length === 1 && segments[0] !== '*') {
    const leaf = String(segments[0] || '').trim().toLowerCase()
    const findLeaf = (value: unknown, depth = 0): unknown[] => {
      if (!leaf || depth > 8 || value == null) return []
      const parsedJson = parseObjectLikeJsonString(value)
      if (parsedJson && (Array.isArray(parsedJson) || typeof parsedJson === 'object')) {
        value = parsedJson
      }
      if (Array.isArray(value)) {
        return value.flatMap((item) => findLeaf(item, depth + 1))
      }
      if (typeof value === 'object') {
        const obj = value as Record<string, unknown>
        const directKey = Object.keys(obj).find((key) => String(key || '').trim().toLowerCase() === leaf)
        if (directKey) return [obj[directKey]]
        return Object.values(obj).flatMap((item) => findLeaf(item, depth + 1))
      }
      return []
    }
    const leafValues = findLeaf(row)
    if (leafValues.length > 0) return leafValues
  }

  const walk = (current: unknown, segIndex: number, depth: number) => {
    if (depth > 32) return
    const parsedJson = parseObjectLikeJsonString(current)
    if (parsedJson && (Array.isArray(parsedJson) || typeof parsedJson === 'object')) {
      current = parsedJson
    }
    if (segIndex >= segments.length) {
      out.push(current)
      return
    }
    if (current === null || current === undefined) return
    const seg = segments[segIndex]
    if (Array.isArray(current)) {
      if (seg === '*') {
        current.forEach((item) => walk(item, segIndex + 1, depth + 1))
        return
      }
      const idx = Number(seg)
      if (!Number.isInteger(idx) || idx < 0 || idx >= current.length) return
      walk(current[idx], segIndex + 1, depth + 1)
      return
    }
    if (typeof current === 'object') {
      const obj = current as Record<string, unknown>
      if (seg === '*') {
        Object.values(obj).forEach((value) => walk(value, segIndex + 1, depth + 1))
        return
      }
      if (seg in obj) {
        walk(obj[seg], segIndex + 1, depth + 1)
        return
      }
      const lowerSeg = String(seg || '').toLowerCase()
      const hitKey = Object.keys(obj).find((key) => String(key || '').toLowerCase() === lowerSeg)
      if (hitKey) {
        walk(obj[hitKey], segIndex + 1, depth + 1)
        return
      }
      // Fallback: when source row stores JSON as string in a parent column,
      // attempt to resolve the same path inside embedded object-like payloads.
      Object.values(obj).forEach((value) => {
        const embedded = parseObjectLikeJsonString(value)
        if (embedded && (Array.isArray(embedded) || typeof embedded === 'object')) {
          walk(embedded, segIndex, depth + 1)
        }
      })
      return
    }
  }

  walk(row, 0, 0)
  if (out.length <= 1) return out
  const seen = new Set<string>()
  const deduped: unknown[] = []
  out.forEach((value) => {
    let key = ''
    try {
      key = JSON.stringify(value)
    } catch {
      key = String(value)
    }
    if (!seen.has(key)) {
      seen.add(key)
      deduped.push(value)
    }
  })
  return deduped
}

function readPathValue(row: Record<string, unknown>, path: string): { found: boolean; value: unknown } {
  const values = readPathValues(row, path)
  if (!values.length) return { found: false, value: undefined }
  return { found: true, value: values[0] }
}

function hasMeaningfulValue(value: unknown): boolean {
  if (value === null || value === undefined) return false
  if (typeof value === 'string') return value.trim().length > 0
  if (Array.isArray(value)) return value.length > 0
  if (typeof value === 'object') return Object.keys(value as Record<string, unknown>).length > 0
  return true
}

function filterRowsByPrimaryKey(
  rows: Array<Record<string, unknown>>,
  primaryKeyPath: string,
): Array<Record<string, unknown>> {
  const path = String(primaryKeyPath || '').trim()
  if (!path) return rows
  return rows.filter((row) => {
    const hit = readPathValue(row, path)
    if (!hit.found) return false
    return hasMeaningfulValue(hit.value)
  })
}

