        <Text style={{ color: 'var(--app-text-subtle)', fontSize: 12 }}>
          Node: {activeProfileNodeSummary?.node_id || selectedNodeId || 'N/A'} | Showing {activeProfileDocuments.length} sample profile document(s).
        </Text>
        <Select
