                            <InputNumber size="small" min={0} max={24} value={mlopsStage3SARIMAPPDraft} onChange={(v) => setMLOpsStage3SARIMAPPDraft(Number.isFinite(Number(v)) ? Math.trunc(Number(v)) : 1)} style={{ width: '100%', marginTop: 4 }} />
